// POST: Fetch profile picture URL for a JID
export async function POST(
    request: NextRequest,
    { params }: { params: Promise<{ sessionId: string; jid: string }> }
) {
    try {
        const user = await getAuthenticatedUser(request);
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { sessionId, jid } = await params;

        // Check if user can access this session
        const canAccess = await canAccessSession(user.id, user.role, sessionId);
        if (!canAccess) {
            return NextResponse.json({ error: "Forbidden - Cannot access this session" }, { status: 403 });
        }

        const instance = waManager.getInstance(sessionId);
        if (!instance?.socket) {
            return NextResponse.json({ error: "Session not ready" }, { status: 503 });
        }

        const decodedJid = decodeURIComponent(jid);

        // Fetch profile picture
        try {
            const profilePicUrl = await instance.socket.profilePictureUrl(decodedJid, 'image');
            
            return NextResponse.json({ 
                success: true,
                jid: decodedJid,
                profilePicUrl
            });
        } catch (error: any) {
            // If no profile picture exists
            if (error.message?.includes('404') || error.message?.includes('not-found')) {
                return NextResponse.json({ 
                    success: true,
                    jid: decodedJid,
                    profilePicUrl: null,
                    message: "No profile picture found"
                });
            }
            throw error;
        }

    } catch (error) {
        console.error("Fetch profile picture error:", error);
        return NextResponse.json({ error: "Failed to fetch profile picture" }, { status: 500 });
    }
}

import { prisma } from "@/lib/prisma";
import { NextResponse, NextRequest } from "next/server";
import { getAuthenticatedUser, canAccessSession } from "@/lib/api-auth";

export async function GET(
    request: NextRequest,
    { params }: { params: Promise<{ sessionId: string, jid: string }> }
) {
    const { sessionId, jid } = await params;
    const decodedJid = decodeURIComponent(jid);

    try {
        const user = await getAuthenticatedUser(request);
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        // Check if user can access this session
        const canAccess = await canAccessSession(user.id, user.role, sessionId);
        if (!canAccess) {
            return NextResponse.json({ error: "Forbidden - Cannot access this session" }, { status: 403 });
        }

        // Get the database Session ID (cuid) from the sessionId string
        const session = await prisma.session.findUnique({
            where: { sessionId },
            select: { id: true }
        });

        if (!session) {
            return NextResponse.json({ error: 'Session not found' }, { status: 404 });
        }

        const dbSessionId = session.id;

        const messages = await prisma.message.findMany({
            where: { 
                sessionId: dbSessionId,
                remoteJid: decodedJid 
            },
            orderBy: { timestamp: 'desc' }, // Fetch NEWEST first
            take: 100
        });

        // Reverse to show oldest -> newest
        messages.reverse();

        // Enrich with participant info if it's a group
        if (decodedJid.endsWith('@g.us')) {
            const group = await prisma.group.findUnique({
                where: {
                    sessionId_jid: {
                        sessionId: dbSessionId,
                        jid: decodedJid
                    }
                },
                select: { participants: true }
            });

            if (group && group.participants) {
                const parts = group.participants as any[];
                
                const enrichedMessages = messages.map((msg: any) => {
                    const sender = msg.senderJid || msg.remoteJid; // Fallback
                    const participant = parts.find(p => p.id === sender);
                    
                    return {
                        ...msg,
                        sender: participant || sender // Replace or add sender field with object or string
                    };
                });
                
                return NextResponse.json(enrichedMessages);
            }
        }

        return NextResponse.json(messages);
    } catch (error) {
        console.error("Fetch messages error:", error);
        return NextResponse.json({ error: 'Failed to fetch messages' }, { status: 500 });
    }
}

import { NextResponse, NextRequest } from "next/server";
import { waManager } from "@/modules/whatsapp/manager";
import { getAuthenticatedUser, canAccessSession } from "@/lib/api-auth";

// POST: Check if number is on WhatsApp
export async function POST(
    request: NextRequest,
    { params }: { params: Promise<{ sessionId: string }> }
) {
    try {
        const user = await getAuthenticatedUser(request);
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { sessionId } = await params;
        const body = await request.json();
        const { numbers } = body;

        if (!numbers || !Array.isArray(numbers)) {
            return NextResponse.json({ 
                error: "numbers (array) is required" 
            }, { status: 400 });
        }

        if (numbers.length === 0) {
            return NextResponse.json({ error: "At least one number is required" }, { status: 400 });
        }

        if (numbers.length > 50) {
            return NextResponse.json({ error: "Maximum 50 numbers per request" }, { status: 400 });
        }

        // Check if user can access this session
        const canAccess = await canAccessSession(user.id, user.role, sessionId);
        if (!canAccess) {
            return NextResponse.json({ error: "Forbidden - Cannot access this session" }, { status: 403 });
        }

        const instance = waManager.getInstance(sessionId);
        if (!instance?.socket) {
            return NextResponse.json({ error: "Session not ready" }, { status: 503 });
        }

        // Check numbers on WhatsApp
        const results = await Promise.all(
            numbers.map(async (number: string) => {
                try {
                    const checkResult = await instance.socket!.onWhatsApp(number);
                    // onWhatsApp returns array of results
                    const result = Array.isArray(checkResult) && checkResult.length > 0 ? checkResult[0] : null;
                    return {
                        number,
                        exists: result?.exists || false,
                        jid: result?.jid || null
                    };
                } catch (error) {
                    return {
                        number,
                        exists: false,
                        jid: null,
                        error: "Invalid number format"
                    };
                }
            })
        );

        return NextResponse.json({ 
            success: true,
            results
        });

    } catch (error) {
        console.error("Check WhatsApp error:", error);
        return NextResponse.json({ error: "Failed to check numbers" }, { status: 500 });
    }
}

import { NextResponse, NextRequest } from "next/server";
import { waManager } from "@/modules/whatsapp/manager";
import { getAuthenticatedUser, canAccessSession } from "@/lib/api-auth";
import Sticker from "wa-sticker-formatter";

export async function POST(
    request: NextRequest,
    { params }: { params: Promise<{ sessionId: string }> }
) {
    console.warn('[DEPRECATED] POST /api/chat/[sessionId]/send is deprecated. Use POST /api/messages/[sessionId]/[jid]/send instead.');
    try {
        const user = await getAuthenticatedUser(request);
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { sessionId } = await params;
        const body = await request.json();
        const { jid, message, mentions } = body;

        if (!jid || !message) {
            return NextResponse.json({ error: "jid and message are required" }, { status: 400 });
        }

        // Check if user can access this session
        const canAccess = await canAccessSession(user.id, user.role, sessionId);
        if (!canAccess) {
            return NextResponse.json({ error: "Forbidden - Cannot access this session" }, { status: 403 });
        }

        const instance = waManager.getInstance(sessionId);
        if (!instance) {
            return NextResponse.json({ error: "Session not found or disconnected" }, { status: 404 });
        }

        const socket = instance.socket;
        if (!socket) {
             return NextResponse.json({ error: "Socket not ready" }, { status: 503 });
        }

        // Process Message
        let msgPayload = message;

        // Custom Handler for Sticker URL
        if (msgPayload.sticker && (msgPayload.sticker.url || typeof msgPayload.sticker === 'string')) {
            const url = msgPayload.sticker.url || msgPayload.sticker;
            
            try {
                const res = await fetch(url);
                if (!res.ok) throw new Error(`Failed to fetch sticker media: ${res.statusText}`);
                const buffer = await res.arrayBuffer();
                
                const sticker = new Sticker(Buffer.from(buffer), {
                    pack: msgPayload.sticker.pack || "HAZA-WA Bot",
                    author: msgPayload.sticker.author || "HAZA-WA",
                    type: "full",
                    quality: 50
                });

                const stickerBuffer = await sticker.toBuffer();
                msgPayload = { sticker: stickerBuffer };

            } catch (e) {
                console.error("Sticker generation from URL failed:", e);
                return NextResponse.json({ error: `Failed to generate sticker from URL: ${(e as any).message}` }, { status: 400 });
            }
        }

        // Send Message
        // Ensure mentions are passed in options and also in message content if it's a text message
        if (msgPayload.text && mentions && Array.isArray(mentions)) {
             msgPayload.mentions = mentions;
        }

        await socket.sendMessage(jid, msgPayload, { mentions: mentions || [] } as any);

        return NextResponse.json({ success: true });
    } catch (error) {
        console.error("Send message error:", error);
        return NextResponse.json({ error: "Failed to send message" }, { status: 500 });
    }
}

