import { NextResponse, NextRequest } from "next/server";
import { waManager } from "@/modules/whatsapp/manager";
import { getAuthenticatedUser, canAccessSession } from "@/lib/api-auth";
import Sticker from "wa-sticker-formatter";

/**
 * @deprecated This endpoint is deprecated. Use POST /api/chat/{sessionId}/send instead.
 * This endpoint will be removed in a future version.
 */
export async function POST(request: NextRequest) {
    try {
        const user = await getAuthenticatedUser(request);
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const body = await request.json();
        const { sessionId, jid, message, mentions } = body;

        // Log deprecation warning
        console.warn('[DEPRECATED] POST /api/chat/send is deprecated. Use POST /api/messages/[sessionId]/[jid]/send instead.');

        if (!sessionId || !jid || !message) {
            return NextResponse.json({ error: "sessionId, jid, and message are required" }, { status: 400 });
        }

        // Check if user can access this session
        const canAccess = await canAccessSession(user.id, user.role, sessionId);
        if (!canAccess) {
            return NextResponse.json({ error: "Forbidden - Cannot access this session" }, { status: 403 });
        }

        const instance = waManager.getInstance(sessionId);
        if (!instance) {
            return NextResponse.json({ error: "Session not found or disconnected" }, { status: 404 });
        }

        const socket = instance.socket;
        if (!socket) {
             return NextResponse.json({ error: "Socket not ready" }, { status: 503 });
        }

        // Process Message
        let msgPayload = message;

        // Custom Handler for Sticker URL
        if (msgPayload.sticker && (msgPayload.sticker.url || typeof msgPayload.sticker === 'string')) {
            const url = msgPayload.sticker.url || msgPayload.sticker;
            
            try {
                const res = await fetch(url);
                if (!res.ok) throw new Error(`Failed to fetch sticker media: ${res.statusText}`);
                const buffer = await res.arrayBuffer();
                
                const sticker = new Sticker(Buffer.from(buffer), {
                    pack: msgPayload.sticker.pack || "HAZA-WA Bot",
                    author: msgPayload.sticker.author || "HAZA-WA",
                    type: "full",
                    quality: 50
                });

                const stickerBuffer = await sticker.toBuffer();
                msgPayload = { sticker: stickerBuffer };

            } catch (e) {
                console.error("Sticker generation from URL failed:", e);
                return NextResponse.json({ error: `Failed to generate sticker from URL: ${(e as any).message}` }, { status: 400 });
            }
        }

        // Send Message
        // Ensure mentions are passed in options and also in message content if it's a text message
        if (msgPayload.text && mentions && Array.isArray(mentions)) {
             msgPayload.mentions = mentions;
        }

        await socket.sendMessage(jid, msgPayload, { mentions: mentions || [] } as any);

        return NextResponse.json({ success: true });
    } catch (error) {
        console.error("Send message error:", error);
        return NextResponse.json({ error: "Failed to send message" }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getAuthenticatedUser, canAccessSession } from "@/lib/api-auth";

export async function GET(
    req: NextRequest,
    { params }: { params: Promise<{ sessionId: string }> }
) {
    try {
        const user = await getAuthenticatedUser(req);
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { sessionId } = await params;
        const { searchParams } = new URL(req.url);
        const page = parseInt(searchParams.get("page") || "1");
        const limit = parseInt(searchParams.get("limit") || "10");
        const search = searchParams.get("search") || "";

        // Check if user can access this session
        const canAccess = await canAccessSession(user.id, user.role, sessionId);
        if (!canAccess) {
            return NextResponse.json({ error: "Forbidden - Cannot access this session" }, { status: 403 });
        }

        // Resolve sessionId string to database ID (CUID)
        const sessionData = await prisma.session.findUnique({
            where: { sessionId: sessionId },
            select: { id: true }
        });

        if (!sessionData) {
            return NextResponse.json({ error: "Session not found" }, { status: 404 });
        }

        const where: any = {
            sessionId: sessionData.id,
        };

        if (search) {
            where.OR = [
                { name: { contains: search } },
                { notify: { contains: search } },
                { verifiedName: { contains: search } },
                { jid: { contains: search } },
                { remoteJidAlt: { contains: search } }
            ];
        }

        const [contacts, total] = await Promise.all([
            prisma.contact.findMany({
                where,
                skip: (page - 1) * limit,
                take: limit,
                orderBy: { name: 'asc' }
            }),
            prisma.contact.count({ where })
        ]);

        return NextResponse.json({
            data: contacts,
            meta: {
                total,
                page,
                limit,
                totalPages: Math.ceil(total / limit)
            }
        });
    } catch (error) {
        console.error("Error fetching contacts:", error);
        return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { auth } from "@/lib/auth";

export async function GET(req: NextRequest) {
    const session = await auth();
    if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const { searchParams } = new URL(req.url);
    const sessionIdParam = searchParams.get("sessionId");

    if (sessionIdParam) {
        console.warn(`[DEPRECATED] GET /api/contacts?sessionId=${sessionIdParam} is deprecated. Use GET /api/contacts/${sessionIdParam} instead.`);
    }

    const page = parseInt(searchParams.get("page") || "1");
    const limit = parseInt(searchParams.get("limit") || "10");
    const search = searchParams.get("search") || "";

    if (!sessionIdParam) {
        return NextResponse.json({ error: "Session ID is required" }, { status: 400 });
    }

    // Resolve sessionId string to database ID (CUID)
    const sessionData = await prisma.session.findUnique({
        where: { sessionId: sessionIdParam },
        select: { id: true }
    });

    if (!sessionData) {
        return NextResponse.json({ error: "Session not found" }, { status: 404 });
    }

    const where: any = {
        sessionId: sessionData.id,
    };

    if (search) {
        where.OR = [
            { name: { contains: search } }, // Case insensitive usually handled by DB collation or use mode: 'insensitive' if Postgres
            { notify: { contains: search } },
            { verifiedName: { contains: search } },
            { jid: { contains: search } },
            { remoteJidAlt: { contains: search } }
        ];
    }

    try {
        const [contacts, total] = await Promise.all([
            prisma.contact.findMany({
                where,
                skip: (page - 1) * limit,
                take: limit,
                orderBy: { name: 'asc' } // Default sort
            }),
            prisma.contact.count({ where })
        ]);

        return NextResponse.json({
            data: contacts,
            meta: {
                total,
                page,
                limit,
                totalPages: Math.ceil(total / limit)
            }
        });
    } catch (error) {
        console.error("Error fetching contacts:", error);
        return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
}

import { NextResponse, NextRequest } from "next/server";
import { waManager } from "@/modules/whatsapp/manager";
import { getAuthenticatedUser, canAccessSession } from "@/lib/api-auth";

// PUT: Update group description
export async function PUT(
    request: NextRequest,
    { params }: { params: Promise<{ sessionId: string; jid: string }> }
) {
    try {
        const user = await getAuthenticatedUser(request);
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }
        
        const { sessionId, jid } = await params;
        const decodedJid = decodeURIComponent(jid);
        const body = await request.json();
        const { description } = body;

        // Description can be empty string to remove
        if (description && description.length > 512) {
            return NextResponse.json({ error: "Description must be 512 characters or less" }, { status: 400 });
        }

        // Check if user can access this session
        const canAccess = await canAccessSession(user.id, user.role, sessionId);
        if (!canAccess) {
            return NextResponse.json({ error: "Forbidden - Cannot access this session" }, { status: 403 });
        }

        const instance = waManager.getInstance(sessionId);
        if (!instance?.socket) {
            return NextResponse.json({ error: "Session not ready" }, { status: 503 });
        }

        // Update group description
        await instance.socket.groupUpdateDescription(decodedJid, description || "");

        return NextResponse.json({ 
            success: true, 
            message: description ? "Group description updated successfully" : "Group description removed",
            description: description || null
        });

    } catch (error: any) {
        console.error("Update group description error:", error);
        
        // Handle specific errors
        if (error.message?.includes("not-admin") || error.message?.includes("forbidden")) {
            return NextResponse.json({ error: "Bot must be admin to update group description" }, { status: 403 });
        }
        
        return NextResponse.json({ error: "Failed to update group description" }, { status: 500 });
    }
}

import { NextResponse, NextRequest } from "next/server";
import { waManager } from "@/modules/whatsapp/manager";
import { getAuthenticatedUser, canAccessSession } from "@/lib/api-auth";

// PUT: Toggle ephemeral/disappearing messages
export async function PUT(
    request: NextRequest,
    { params }: { params: Promise<{ sessionId: string; jid: string }> }
) {
    try {
        const user = await getAuthenticatedUser(request);
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }
        
        const { sessionId, jid } = await params;
        const decodedJid = decodeURIComponent(jid);
        const body = await request.json();
        const { expiration } = body; // expiration is duration in seconds

        if (expiration === undefined) {
            return NextResponse.json({ 
                error: "expiration is required" 
            }, { status: 400 });
        }

        // Expiration values: 0 (off), 86400 (1 day), 604800 (7 days), 7776000 (90 days)
        const validExpirations = [0, 86400, 604800, 7776000];
        if (!validExpirations.includes(expiration)) {
            return NextResponse.json({ 
                error: "Invalid expiration. Must be 0 (off), 86400 (1 day), 604800 (7 days), or 7776000 (90 days)" 
            }, { status: 400 });
        }

        // Check if user can access this session
        const canAccess = await canAccessSession(user.id, user.role, sessionId);
        if (!canAccess) {
            return NextResponse.json({ error: "Forbidden - Cannot access this session" }, { status: 403 });
        }

        const instance = waManager.getInstance(sessionId);
        if (!instance?.socket) {
            return NextResponse.json({ error: "Session not ready" }, { status: 503 });
        }

        // Toggle ephemeral messages
        await instance.socket.groupToggleEphemeral(decodedJid, expiration);

        const expirationLabels: Record<number, string> = {
            0: 'off',
            86400: '1 day',
            604800: '7 days',
            7776000: '90 days'
        };

        return NextResponse.json({ 
            success: true,
            message: `Disappearing messages ${expiration === 0 ? 'disabled' : 'enabled'}`,
            expiration,
            expirationLabel: expirationLabels[expiration]
        });

    } catch (error: any) {
        console.error("Toggle ephemeral error:", error);
        
        if (error.message?.includes("not-admin") || error.message?.includes("forbidden")) {
            return NextResponse.json({ 
                error: "Bot must be admin to toggle ephemeral messages" 
            }, { status: 403 });
        }
        
        return NextResponse.json({ error: "Failed to toggle ephemeral messages" }, { status: 500 });
    }
}

