                setNewKeyword("");
                setNewResponse("");
                setNewMatchType("EXACT");
                setNewIsMedia(false);
                setNewMediaUrl("");
                setNewTriggerType("ALL"); // Reset newTriggerType
                setEditingId(null);
                fetchRules(selectedSessionId);
            } else {
                toast.error(editingId ? "Failed to update rule" : "Failed to create rule");
            }
        } catch (error) {
            toast.error("An error occurred");
        }
    };

    const confirmDelete = async () => {
        if (!deleteId) return;
        try {
            const res = await fetch(`/api/autoreplies/${selectedSessionId}/${deleteId}`, { method: "DELETE" });
            if (res.ok) {
                toast.success("Rule deleted");
                setRules(rules.filter(r => r.id !== deleteId));
            } else {
                toast.error("Failed to delete rule");
            }
        } catch (error) {
            toast.error("Failed to delete rule");
        } finally {
            setDeleteId(null);
        }
    };

    const filteredRules = rules.filter(r =>
        r.keyword.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.response.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <SessionGuard>
            <div className="space-y-6">
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold flex items-center gap-2">
                            <MessageSquare className="h-6 w-6" /> Auto Reply
                        </h1>
                        <p className="text-muted-foreground">Automatically reply to incoming messages based on keywords.</p>
                    </div>

                    <div className="flex items-center gap-2">
                        <Button variant="outline" onClick={() => selectedSessionId && fetchRules(selectedSessionId)} disabled={loading || !selectedSessionId}>
                            <RefreshCw className={`h-4 w-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
                            Refresh
                        </Button>
                        <Button onClick={() => {
                            setEditingId(null);
                            setNewKeyword("");
                            setNewResponse("");
                            setNewMatchType("EXACT");
                            setNewIsMedia(false);
                            setNewMediaUrl("");
                            setNewTriggerType("ALL"); // Reset newTriggerType
                            setShowForm(!showForm);
                        }} disabled={!selectedSessionId}>
                            <Plus className="h-4 w-4 mr-2" /> Add Rule
                        </Button>
                    </div>
                </div>

                <SearchFilter
                    placeholder="Search rules..."
                    onSearch={setSearchTerm}
                />

                {/* New/Edit Rule Form */}
                {showForm && (
                    <Card className="border-2 border-primary/20">
                        <CardHeader>
                            <CardTitle>{editingId ? "Edit Auto Reply Rule" : "New Auto Reply Rule"}</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="space-y-2">
                                <Label>Keyword</Label>
                                <Input
                                    value={newKeyword}
                                    onChange={e => setNewKeyword(e.target.value)}
                                    placeholder="e.g. !hello"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label>Match Type</Label>
                                    <Select value={newMatchType} onValueChange={setNewMatchType}>
                                        <SelectTrigger>
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="EXACT">Exact Match</SelectItem>
                                            <SelectItem value="CONTAINS">Contains</SelectItem>
                                            <SelectItem value="STARTS_WITH">Starts With</SelectItem>
                                            <SelectItem value="REGEX">Regex</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-2">
                                    <Label>Respond IN</Label>
                                    <Select value={newTriggerType} onValueChange={setNewTriggerType}>
                                        <SelectTrigger>
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="ALL">All Chats</SelectItem>
                                            <SelectItem value="PRIVATE">Private Only</SelectItem>
                                            <SelectItem value="GROUP">Group Only</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>

                            <div className="space-y-4 border p-3 rounded-md">
                                <div className="flex items-center gap-2">
                                    <input
                                        type="checkbox"
                                        id="isMedia"
                                        className="h-4 w-4 rounded border-gray-300"
                                        checked={newIsMedia}
                                        onChange={(e) => setNewIsMedia(e.target.checked)}
                                    />
                                    <Label htmlFor="isMedia">Send Media</Label>
                                </div>

                                {newIsMedia && (
                                    <div className="space-y-2">
                                        <Label>Media URL</Label>
                                        <Input
                                            placeholder="https://example.com/image.jpg"
                                            value={newMediaUrl}
                                            onChange={(e) => setNewMediaUrl(e.target.value)}
                                        />
                                        <p className="text-xs text-muted-foreground">Direct link to image, video, or document.</p>
                                    </div>
                                )}
                            </div>
                            <div className="space-y-2">
                                <Label>Response Message</Label>
                                <Textarea
                                    value={newResponse}
                                    onChange={e => setNewResponse(e.target.value)}
                                    placeholder="Hello! How can I help you?"
                                    rows={4}
                                />
                            </div>
                            <div className="flex justify-end gap-2">
                                <Button variant="ghost" onClick={() => {
                                    setShowForm(false);
                                    setEditingId(null);
                                    setNewKeyword("");
                                    setNewResponse("");
                                    setNewIsMedia(false);
                                    setNewMediaUrl("");
                                }}>Cancel</Button>
                                <Button onClick={handleSaveRule}>{editingId ? "Update" : "Save"}</Button>
                            </div>
                        </CardContent>
                    </Card>
                )}

                {/* Rules List */}
                {loading ? (
                    <div className="text-center p-8">Loading rules...</div>
                ) : filteredRules.length === 0 ? (
                    <div className="text-center p-8 text-muted-foreground border rounded-lg bg-slate-50">
                        {selectedSessionId ? "No auto reply rules found matching criteria." : "No session selected."}
                    </div>
                ) : (
                    <div className="grid gap-4">
                        {filteredRules.map(rule => (
                            <Card key={rule.id}>
                                <CardContent className="flex justify-between items-center p-4">
                                    <div>
                                        <div className="font-bold flex items-center gap-2">
                                            {rule.keyword}
                                            <span className="text-xs bg-slate-100 px-2 py-0.5 rounded text-slate-500 font-normal">{rule.matchType}</span>
                                        </div>
                                        <div className="text-sm text-muted-foreground mt-1">{rule.response}</div>
                                    </div>
                                    <div className="flex gap-2">
                                        <Button variant="ghost" size="sm" onClick={() => handleEdit(rule)}>
                                            Edit
                                        </Button>
                                        <Button variant="ghost" size="icon" onClick={() => setDeleteId(rule.id)} className="text-destructive hover:text-destructive hover:bg-red-50">
                                            <Trash2 className="h-4 w-4" />
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}

                <AlertDialog open={!!deleteId} onOpenChange={(open) => !open && setDeleteId(null)}>
                    <AlertDialogContent>
                        <AlertDialogHeader>
                            <AlertDialogTitle>Delete Rule?</AlertDialogTitle>
                            <AlertDialogDescription>
                                This will verify delete this auto reply rule.
                            </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                            <AlertDialogCancel>Cancel</AlertDialogCancel>
                            <AlertDialogAction onClick={confirmDelete} className="bg-red-600 hover:bg-red-700">Delete</AlertDialogAction>
                        </AlertDialogFooter>
                    </AlertDialogContent>
                </AlertDialog>
            </div>
        </SessionGuard>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useSession } from "@/components/dashboard/session-provider";
import { SessionGuard } from "@/components/dashboard/session-guard";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { Loader2, Bot, Wand2, Shield, Activity, Image as ImageIcon, MessageSquare } from "lucide-react";

interface BotConfig {
    id?: string;
    enabled: boolean;
    botName: string;
    botMode: 'ALL' | 'OWNER' | 'SPECIFIC' | 'BLACKLIST';
    botAllowedJids: string[];
    botBlockedJids: string[];
    autoReplyMode: 'ALL' | 'OWNER' | 'SPECIFIC' | 'BLACKLIST';
    autoReplyAllowedJids: string[];
    autoReplyBlockedJids: string[];
    enableSticker: boolean;
    enableVideoSticker: boolean;
    maxStickerDuration: number;
    enablePing: boolean;
    enableUptime: boolean;
    removeBgApiKey: string | null;
}

export default function BotSettingsPage() {
    const { sessionId: currentSessionId } = useSession();
    const [config, setConfig] = useState<BotConfig>({
        enabled: true,
        botName: "HAZA-WA Bot",
        botMode: 'OWNER',
        botAllowedJids: [],
        botBlockedJids: [],
        autoReplyMode: 'ALL',
        autoReplyAllowedJids: [],
        autoReplyBlockedJids: [],
        enableSticker: true,
        enableVideoSticker: true,
        maxStickerDuration: 10,
        enablePing: true,
        enableUptime: true,
        removeBgApiKey: ""
    });
    const [isLoading, setIsLoading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);

    // Helpers to manage JID text area
    const [botJidsText, setBotJidsText] = useState("");
    const [botBlockedJidsText, setBotBlockedJidsText] = useState("");
    const [autoReplyJidsText, setAutoReplyJidsText] = useState("");
    const [autoReplyBlockedJidsText, setAutoReplyBlockedJidsText] = useState("");

    useEffect(() => {
        if (currentSessionId) {
            fetchConfig();
        }
    }, [currentSessionId]);

    const fetchConfig = async () => {
        if (!currentSessionId) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/sessions/${currentSessionId}/bot-config`);
            if (res.ok) {
                const data = await res.json();
                setConfig({
                    ...data,
                    botName: data.botName || "HAZA-WA Bot",
                    botMode: data.botMode || 'OWNER',
                    autoReplyMode: data.autoReplyMode || 'ALL',
                    botAllowedJids: Array.isArray(data.botAllowedJids) ? data.botAllowedJids : [],
                    botBlockedJids: Array.isArray(data.botBlockedJids) ? data.botBlockedJids : [],
                    autoReplyAllowedJids: Array.isArray(data.autoReplyAllowedJids) ? data.autoReplyAllowedJids : [],
                    autoReplyBlockedJids: Array.isArray(data.autoReplyBlockedJids) ? data.autoReplyBlockedJids : [],
                    enableVideoSticker: data.enableVideoSticker !== undefined ? data.enableVideoSticker : true,
                    maxStickerDuration: data.maxStickerDuration || 10,
                    removeBgApiKey: data.removeBgApiKey || ""
                });
                // Init text areas
                setBotJidsText((data.botAllowedJids || []).join('\n'));
                setBotBlockedJidsText((data.botBlockedJids || []).join('\n'));
                setAutoReplyJidsText((data.autoReplyAllowedJids || []).join('\n'));
                setAutoReplyBlockedJidsText((data.autoReplyBlockedJids || []).join('\n'));
            }
        } catch (error) {
            console.error("Failed to fetch config", error);
            toast.error("Failed to load bot settings");
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async () => {
        if (!currentSessionId) return;
        setIsSaving(true);

        // Parse JIDs
        const botJids = botJidsText.split('\n').map(s => s.trim()).filter(Boolean);
        const botBlockedJids = botBlockedJidsText.split('\n').map(s => s.trim()).filter(Boolean);
        const autoReplyJids = autoReplyJidsText.split('\n').map(s => s.trim()).filter(Boolean);
        const autoReplyBlockedJids = autoReplyBlockedJidsText.split('\n').map(s => s.trim()).filter(Boolean);

        const payload = {
            ...config,
            botAllowedJids: botJids,
            botBlockedJids: botBlockedJids,
            autoReplyAllowedJids: autoReplyJids,
            autoReplyBlockedJids: autoReplyBlockedJids
        };

        try {
            const res = await fetch(`/api/sessions/${currentSessionId}/bot-config`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload)
            });

            if (!res.ok) throw new Error("Failed to save");

            toast.success("Bot settings saved successfully");
        } catch (error) {
            console.error(error);
            toast.error("Failed to save settings");
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <SessionGuard>
            {/* Note: SessionGuard handles the no session state, so we can assume currentSessionId exists in logic, but TS might complain so we keep safe checks if needed or rely on guard blocking it */}
            {isLoading ? (
                <div className="flex items-center justify-center min-h-[60vh]">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : (
                <div className="container max-w-4xl py-6 space-y-8">
                    <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                        <div>
                            <h1 className="text-3xl font-bold tracking-tight">Bot Magic Settings ≡ƒ¬ä</h1>
                            <p className="text-muted-foreground">
                                Configure your WhatsApp Bot features and "Magic Commands".
                            </p>
                        </div>
                        <Button onClick={handleSave} disabled={isSaving}>
                            {isSaving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Save Changes
                        </Button>
                    </div>

                    <div className="grid gap-6">
                        {/* Main Switch */}
                        <Card className={config.enabled ? "border-primary/50 bg-primary/5" : ""}>
                            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                                <div className="space-y-1">
                                    <CardTitle className="text-xl">Enable Bot Features</CardTitle>
                                    <CardDescription>
                                        Turn on/off all magic commands for this session.
                                    </CardDescription>
                                </div>
                                <Switch
                                    checked={config.enabled}
                                    onCheckedChange={(checked) => setConfig(prev => ({ ...prev, enabled: checked }))}
                                />
                            </CardHeader>
                        </Card>

                        {/* Bot Identity */}
                        <Card>
                            <CardHeader>
                                <CardTitle className="text-lg flex items-center gap-2">
                                    <Bot className="h-5 w-5" /> Bot Identity
                                </CardTitle>
                                <CardDescription>
                                    Customize how your bot identifies itself.
                                </CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="space-y-2">
                                    <Label>Bot Name</Label>
                                    <Input
                                        placeholder="e.g. HAZA-WA Bot"
                                        value={config.botName || ""}
                                        onChange={(e) => setConfig(prev => ({ ...prev, botName: e.target.value }))}
                                    />
                                    <p className="text-xs text-muted-foreground">
                                        Displayed in stickermaker watermarks and help menus.
                                    </p>
                                </div>
                            </CardContent>
                        </Card>

                        {/* Access Control */}
                        <Card>
                            <CardHeader>
                                <CardTitle className="text-lg flex items-center gap-2">
                                    <Shield className="h-5 w-5" /> Access Control
                                </CardTitle>
                                <CardDescription>
                                    Who can use the bot and trigger auto-replies?
                                </CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-8">
                                {/* Bot Commands */}
                                <div className="space-y-4">
                                    <div className="flex flex-col space-y-2 md:flex-row md:space-y-0 md:items-center md:justify-between">
                                        <Label className="text-base flex items-center gap-2">
                                            <Bot className="h-4 w-4" /> Bot Commands Access
                                        </Label>
                                        <Select
                                            value={config.botMode}
                                            onValueChange={(val: any) => setConfig(prev => ({ ...prev, botMode: val }))}
                                        >
                                            <SelectTrigger className="w-full md:w-[200px]">
                                                <SelectValue placeholder="Select Mode" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="OWNER">Owner Only (Me)</SelectItem>
                                                <SelectItem value="ALL">Public (Everyone)</SelectItem>
                                                <SelectItem value="SPECIFIC">Specific Contacts</SelectItem>
                                                <SelectItem value="BLACKLIST">Block Specific Contacts</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <p className="text-sm text-muted-foreground">
                                        Controls who can use commands like <code>#sticker</code>, <code>#ping</code>.
                                    </p>

                                    {config.botMode === 'SPECIFIC' && (
                                        <div className="ml-1 pl-4 border-l-2 border-slate-200 space-y-2">
                                            <Label>Allowed JIDs (one per line)</Label>
                                            <Textarea
                                                placeholder="628123456789@s.whatsapp.net"
                                                value={botJidsText}
                                                onChange={(e) => setBotJidsText(e.target.value)}
                                                className="font-mono text-sm max-h-[150px]"
                                            />
                                            <p className="text-xs text-muted-foreground">Enter specific WhatsApp IDs (JIDs) allowed to use the bot.</p>
                                        </div>
                                    )}

                                    {config.botMode === 'BLACKLIST' && (
                                        <div className="ml-1 pl-4 border-l-2 border-slate-200 space-y-2">
                                            <Label>Blocked JIDs (one per line)</Label>
                                            <Textarea
                                                placeholder="628123456789@s.whatsapp.net"
                                                value={botBlockedJidsText}
                                                onChange={(e) => setBotBlockedJidsText(e.target.value)}
                                                className="font-mono text-sm max-h-[150px]"
                                            />
                                            <p className="text-xs text-muted-foreground">Enter WhatsApp IDs (JIDs) blocked from using the bot.</p>
                                        </div>
                                    )}
                                </div>

                                <div className="border-t" />

                                {/* Auto Reply */}
                                <div className="space-y-4">
                                    <div className="flex flex-col space-y-2 md:flex-row md:space-y-0 md:items-center md:justify-between">
                                        <Label className="text-base flex items-center gap-2">
                                            <MessageSquare className="h-4 w-4" /> Auto Reply Access
                                        </Label>
                                        <Select
                                            value={config.autoReplyMode}
                                            onValueChange={(val: any) => setConfig(prev => ({ ...prev, autoReplyMode: val }))}
                                        >
                                            <SelectTrigger className="w-full md:w-[200px]">
                                                <SelectValue placeholder="Select Mode" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="ALL">Everyone (Public)</SelectItem>
                                                <SelectItem value="OWNER">Owner Only (Me)</SelectItem>
                                                <SelectItem value="SPECIFIC">Specific Contacts</SelectItem>
                                                <SelectItem value="BLACKLIST">Block Specific Contacts</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <p className="text-sm text-muted-foreground">
                                        Controls whose messages trigger Auto Replies.
                                    </p>

                                    {config.autoReplyMode === 'SPECIFIC' && (
                                        <div className="ml-1 pl-4 border-l-2 border-slate-200 space-y-2">
                                            <Label>Allowed JIDs (one per line)</Label>
                                            <Textarea
                                                placeholder="628123456789@s.whatsapp.net"
                                                value={autoReplyJidsText}
                                                onChange={(e) => setAutoReplyJidsText(e.target.value)}
                                                className="font-mono text-sm max-h-[150px]"
                                            />
                                        </div>
                                    )}

                                    {config.autoReplyMode === 'BLACKLIST' && (
                                        <div className="ml-1 pl-4 border-l-2 border-slate-200 space-y-2">
                                            <Label>Blocked JIDs (one per line)</Label>
                                            <Textarea
                                                placeholder="628123456789@s.whatsapp.net"
                                                value={autoReplyBlockedJidsText}
                                                onChange={(e) => setAutoReplyBlockedJidsText(e.target.value)}
                                                className="font-mono text-sm max-h-[150px]"
                                            />
                                        </div>
                                    )}
                                </div>
                            </CardContent>
                        </Card>

                        {/* Features */}
                        <Card>
                            <CardHeader>
                                <CardTitle className="text-lg flex items-center gap-2">
                                    <Wand2 className="h-5 w-5" /> Enabled Features
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="grid md:grid-cols-3 gap-6">
                                <div className="flex items-center justify-between md:block md:space-y-2">
                                    <Label className="flex items-center gap-2">
                                        <ImageIcon className="h-4 w-4" /> Sticker (#sticker)
                                    </Label>
                                    <Switch
                                        checked={config.enableSticker}
                                        onCheckedChange={(checked) => setConfig(prev => ({ ...prev, enableSticker: checked }))}
                                    />
                                </div>

                                <div className="space-y-3 p-3 border rounded-lg">
                                    <div className="flex items-center justify-between">
                                        <Label className="flex items-center gap-2 font-medium">
                                            <ImageIcon className="h-4 w-4" /> Enable Video/GIF
                                        </Label>
                                        <Switch
                                            checked={config.enableSticker && config.enableVideoSticker}
                                            onCheckedChange={(checked) => setConfig(prev => ({ ...prev, enableVideoSticker: checked }))}
                                            disabled={!config.enableSticker}
                                        />
                                    </div>
                                    <div className="flex items-center justify-between gap-4">
                                        <Label className="text-xs text-muted-foreground whitespace-nowrap">
                                            Max Duration
                                        </Label>
                                        <div className="flex items-center gap-2">
                                            <Input
                                                type="number"
                                                min={1}
                                                max={60}
                                                className="h-8 w-20 text-right"
                                                value={config.maxStickerDuration || ""}
                                                onChange={(e) => {
                                                    const val = e.target.value;
                                                    setConfig(prev => ({
                                                        ...prev,
                                                        maxStickerDuration: val === "" ? 0 : parseInt(val)
                                                    }));
                                                }}
                                                disabled={!config.enableVideoSticker}
                                            />
                                            <span className="text-xs text-muted-foreground">sec</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center justify-between md:block md:space-y-2">
                                    <Label className="flex items-center gap-2">
                                        <Activity className="h-4 w-4" /> Ping (#ping)
                                    </Label>
                                    <Switch
                                        checked={config.enablePing}
                                        onCheckedChange={(checked) => setConfig(prev => ({ ...prev, enablePing: checked }))}
                                    />
                                </div>

                                <div className="flex items-center justify-between md:block md:space-y-2">
                                    <Label className="flex items-center gap-2">
                                        <Loader2 className="h-4 w-4" /> Uptime (#uptime)
                                    </Label>
                                    <Switch
                                        checked={config.enableUptime}
                                        onCheckedChange={(checked) => setConfig(prev => ({ ...prev, enableUptime: checked }))}
                                    />
                                </div>
                            </CardContent>
                        </Card>

                        {/* Integrations (RemoveBG) */}
                        <Card>
                            <CardHeader>
                                <CardTitle className="text-lg flex items-center gap-2">
                                    <Shield className="h-5 w-5" /> Integrations
                                </CardTitle>
                                <CardDescription>
                                    Configure external keys for enhanced features.
                                </CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="space-y-2">
                                    <Label>Remove.bg API Key</Label>
                                    <div className="flex gap-2">
                                        <Input
                                            type="password"
                                            placeholder="rb_xxxxxxxxxxxxxxxx"
                                            value={config.removeBgApiKey || ""}
                                            onChange={(e) => setConfig(prev => ({ ...prev, removeBgApiKey: e.target.value }))}
                                        />
                                    </div>
                                    <p className="text-xs text-muted-foreground">
                                        Required for background removal features. Get one at <a href="https://www.remove.bg/api" target="_blank" rel="noopener noreferrer" className="underline hover:text-primary">remove.bg</a>.
                                        <br />Command: <code>#sticker nobg</code>
                                    </p>
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                </div>
            )}
        </SessionGuard>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Slider } from "@/components/ui/slider";
import { RefreshCw, Send, Users } from "lucide-react";
import { toast } from "sonner";

import { useSession } from "@/components/dashboard/session-provider";
import { SessionGuard } from "@/components/dashboard/session-guard";

export default function BroadcastPage() {
    const { sessionId } = useSession();
    const [contacts, setContacts] = useState(""); // Raw text input
    const [message, setMessage] = useState("");
    const [delay, setDelay] = useState([2000]);
    const [loading, setLoading] = useState(false);

    const handleSend = async () => {
        if (!sessionId) return alert("No active session found");
        setLoading(true);

        try {
            // Parse contacts
            const recipients = contacts.split(/[\n,]+/).map(s => s.trim()).filter(Boolean).map(s => {
                // Formatting helper: ensure ends with @s.whatsapp.net if just number
                if (!s.includes('@')) return `${s}@s.whatsapp.net`;
                return s;
            });

            const res = await fetch("/api/messages/broadcast", {
                method: "POST",
                body: JSON.stringify({
                    sessionId,
                    recipients,
                    message: message, // Send as string, API handles conversion
                    delay: delay[0]
                })
            });

            if (res.ok) {
                toast.success("Broadcast started!");
                setContacts("");
                setMessage("");
            } else {
                toast.error("Failed to start broadcast");
            }

        } catch (e) {
            console.error(e);
            toast.error("Error sending broadcast");
        } finally {
            setLoading(false);
        }
    };

    return (
        <SessionGuard>
            <div className="space-y-6">
                <div className="flex justify-between items-center">
                    <h2 className="text-3xl font-bold tracking-tight">Broadcast / Blast</h2>
                </div>

                <div className="grid gap-6 md:grid-cols-2">
                    <Card>
                        <CardHeader>
                            <CardTitle>Recipients</CardTitle>
                            <CardDescription>Enter phone numbers separated by comma or new line.</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="space-y-2">
                                <Label>Target Numbers (e.g., 628123456789)</Label>
                                <Textarea
                                    placeholder="628123456789&#10;628987654321"
                                    className="min-h-[200px]"
                                    value={contacts}
                                    onChange={e => setContacts(e.target.value)}
                                />
                                <p className="text-xs text-muted-foreground">{contacts.split(/[\n,]+/).filter(Boolean).length} numbers identified</p>
                            </div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader>
                            <CardTitle>Message Content</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="space-y-2">
                                <Label>Message</Label>
                                <Textarea
                                    placeholder="Type your message here..."
                                    className="min-h-[150px]"
                                    value={message}
                                    onChange={e => setMessage(e.target.value)}
                                />
                            </div>

                            <div className="space-y-4 pt-4">
                                <div className="space-y-2">
                                    <Label>Delay (ms): {delay[0]}</Label>
                                    <Slider
                                        defaultValue={[2000]}
                                        max={10000}
                                        step={100}
                                        value={delay}
                                        onValueChange={setDelay}
                                    />
                                    <p className="text-xs text-muted-foreground">Randomized delay to prevent ban.</p>
                                </div>

                                <Button className="w-full" onClick={handleSend} disabled={loading || !sessionId}>
                                    {loading ? <RefreshCw className="mr-2 h-4 w-4 animate-spin" /> : <Send className="mr-2 h-4 w-4" />}
                                    Start Broadcast
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </SessionGuard>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useSession } from "@/components/dashboard/session-provider";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow
} from "@/components/ui/table";
import {
    Pagination,
    PaginationContent,
    PaginationItem,
    PaginationLink,
    PaginationNext,
    PaginationPrevious
} from "@/components/ui/pagination";

import { Search, Loader2, User, ChevronDown } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";

interface Contact {
    id: string;
    jid: string;
    name?: string;
    notify?: string;
    verifiedName?: string;
    profilePic?: string;
    remoteJidAlt?: string;
}

export default function ContactListPage() {
    const { sessionId } = useSession();
    const [contacts, setContacts] = useState<Contact[]>([]);
    const [loading, setLoading] = useState(false);

    // Filters
    const [search, setSearch] = useState("");
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState("10");
    const [meta, setMeta] = useState({ total: 0, totalPages: 1 });

    // Debounce Search
    useEffect(() => {
        const timer = setTimeout(() => {
            setPage(1); // Reset to page 1 on search
            fetchContacts();
        }, 500);
        return () => clearTimeout(timer);
    }, [search]);

    // Fetch on page/session/limit change
    useEffect(() => {
        fetchContacts();
    }, [page, sessionId, limit]);

    const fetchContacts = async () => {
        if (!sessionId) return;
        setLoading(true);
        try {
            const params = new URLSearchParams({
                page: page.toString(),
                limit: limit,
                search: search
            });

            const res = await fetch(`/api/contacts/${sessionId}?${params}`);
            const data = await res.json();

            if (res.ok) {
                setContacts(data.data);
                setMeta(data.meta);
            } else {
                setContacts([]);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight">Contacts</h2>
                    <p className="text-muted-foreground">
                        Manage and view your saved contacts.
                    </p>
                </div>
            </div>

            <Card>
                <CardHeader>
                    <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                        <div className="space-y-1">
                            <CardTitle>Contact List</CardTitle>
                            <CardDescription>
                                Total: {meta.total} contacts found
                            </CardDescription>
                        </div>
                        <div className="flex items-center gap-2 w-full md:w-auto">
                            <Select value={limit} onValueChange={(val) => { setLimit(val); setPage(1); }}>
                                <SelectTrigger className="w-[100px]">
                                    <SelectValue placeholder="Limit" />
                                </SelectTrigger>
                                <SelectContent>
                                    {[5, 10, 25, 50, 100, 200, 250, 500, 1000, 2000, 3000].map((l) => (
                                        <SelectItem key={l} value={l.toString()}>
                                            {l}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                            <div className="relative w-full md:w-64">
                                <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                                <Input
                                    placeholder="Search contacts..."
                                    className="pl-8"
                                    value={search}
                                    onChange={(e) => setSearch(e.target.value)}
                                />
                            </div>
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="rounded-md border">
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead className="w-[80px]">Image</TableHead>
                                    <TableHead>Name / Pushname</TableHead>
                                    <TableHead className="hidden md:table-cell">JID (ID)</TableHead>
                                    <TableHead className="hidden md:table-cell">Phone / Alt</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {loading ? (
                                    <TableRow>
                                        <TableCell colSpan={4} className="h-24 text-center">
                                            <div className="flex justify-center items-center gap-2">
                                                <Loader2 className="h-4 w-4 animate-spin" />
                                                Loading...
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                ) : contacts.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={4} className="h-24 text-center">
                                            No contacts found.
                                        </TableCell>
                                    </TableRow>
                                ) : (
                                    contacts.map((contact) => (
                                        <TableRow key={contact.id}>
                                            <TableCell>
                                                <Avatar>
                                                    <AvatarImage src={contact.profilePic || ""} />
                                                    <AvatarFallback><User className="h-4 w-4" /></AvatarFallback>
                                                </Avatar>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex flex-col">
                                                    <span className="font-medium">{contact.name || contact.notify || "Unknown"}</span>
                                                    {contact.verifiedName && (
                                                        <span className="text-xs text-green-600 flex items-center gap-1">
                                                            Γ£ô {contact.verifiedName}
                                                        </span>
                                                    )}
                                                </div>
                                            </TableCell>
                                            <TableCell className="hidden md:table-cell font-mono text-sm text-muted-foreground">
                                                {contact.jid}
                                            </TableCell>
                                            <TableCell className="hidden md:table-cell text-sm">
                                                {contact.remoteJidAlt || "-"}
                                            </TableCell>
                                        </TableRow>
                                    ))
                                )}
                            </TableBody>
                        </Table>
                    </div>

                    {/* Pagination */}
                    {meta.totalPages > 1 && (
                        <div className="mt-4">
                            <Pagination>
                                <PaginationContent>
                                    <PaginationItem>
                                        <Button
                                            variant="ghost"
                                            disabled={page <= 1}
                                            onClick={() => setPage(p => Math.max(1, p - 1))}
                                        >
                                            Previous
                                        </Button>
                                    </PaginationItem>

                                    <PaginationItem>
                                        <span className="text-sm text-muted-foreground mx-4">
                                            Page {page} of {meta.totalPages}
                                        </span>
                                    </PaginationItem>

                                    <PaginationItem>
                                        <Button
                                            variant="ghost"
                                            disabled={page >= meta.totalPages}
                                            onClick={() => setPage(p => Math.min(meta.totalPages, p + 1))}
                                        >
                                            Next
                                        </Button>
                                    </PaginationItem>
                                </PaginationContent>
                            </Pagination>
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Users, Plus, RefreshCw } from "lucide-react";
import { SearchFilter } from "@/components/dashboard/search-filter";
import { useSession } from "@/components/dashboard/session-provider";
import { SessionGuard } from "@/components/dashboard/session-guard";
import { toast } from "sonner"; // Added import

// Define a type for Group if not already defined elsewhere
interface Group {
    id: string;
    subject: string;
    jid: string;
    participants?: any[];
}

export default function GroupsPage() {
    const { sessionId } = useSession();

    const [groups, setGroups] = useState<Group[]>([]);
    const [loading, setLoading] = useState(false);
    const [isCreateOpen, setIsCreateOpen] = useState(false);
    const [newGroupName, setNewGroupName] = useState("");
    const [searchTerm, setSearchTerm] = useState("");

    const fetchGroups = async (sessId: string) => {
        setLoading(true);
        try {
            const res = await fetch(`/api/groups/${sessId}`);
            if (res.ok) {
                const data = await res.json();
                setGroups(data);
            } else {
                setGroups([]);
            }
        } catch (error) {
            toast.error("Failed to fetch groups");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (sessionId) {
            fetchGroups(sessionId);
        } else {
            setGroups([]);
        }
    }, [sessionId]);

    const handleCreateGroup = async () => {
        if (!sessionId || !newGroupName) return;
        try {
            const res = await fetch(`/api/groups/${sessionId}/create`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ sessionId, subject: newGroupName })
            });
            if (res.ok) {
                toast.success("Group created");
                setIsCreateOpen(false);
                setNewGroupName("");
                fetchGroups(sessionId);
            } else {
                toast.error("Failed to create group");
            }
        } catch (error) {
            toast.error("Failed to create group");
        }
    };

    const filteredGroups = groups.filter(g =>
        g.subject.toLowerCase().includes(searchTerm.toLowerCase()) ||
        g.jid.includes(searchTerm)
    );

    return (
        <SessionGuard>
            <div className="space-y-6">
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold flex items-center gap-2">
                            <Users className="h-6 w-6" /> Groups
                        </h1>
                        <p className="text-muted-foreground">
                            {sessionId ? "Manage groups for active session." : "Select a session from the top bar."}
                        </p>
                    </div>
                    <div className="flex items-center gap-2">
                        <Button variant="outline" onClick={() => sessionId && fetchGroups(sessionId)} disabled={loading || !sessionId}>
                            <RefreshCw className={`h-4 w-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
                            Refresh
                        </Button>
                        <Button onClick={() => setIsCreateOpen(true)} disabled={!sessionId}>
                            <Plus className="h-4 w-4 mr-2" /> Create Group
                        </Button>
                    </div>
                </div>

                <SearchFilter
                    placeholder="Search groups..."
                    onSearch={setSearchTerm}
                />

                {/* Create Dialog */}
                {isCreateOpen && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
                        <div className="bg-white p-6 rounded-lg shadow-lg w-96">
                            <h2 className="text-xl font-bold mb-4">Create New Group</h2>
                            <div className="space-y-4">
                                <div>
                                    <Label>Group Subject</Label>
                                    <Input value={newGroupName} onChange={e => setNewGroupName(e.target.value)} placeholder="My New Group" />
                                </div>
                                <div className="flex justify-end gap-2">
                                    <Button variant="ghost" onClick={() => setIsCreateOpen(false)}>Cancel</Button>
                                    <Button onClick={handleCreateGroup}>Create</Button>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Groups List */}
                {loading ? (
                    <div className="text-center p-8">Loading groups...</div>
                ) : filteredGroups.length === 0 ? (
                    <div className="text-center p-8 text-muted-foreground border rounded-lg bg-slate-50">
                        {sessionId ? "No groups found matching criteria." : "No session selected."}
                    </div>
                ) : (
                    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                        {filteredGroups.map(group => (
                            <div key={group.id} className="bg-white p-4 rounded-lg shadow border flex justify-between items-start">
                                <div>
                                    <h3 className="font-bold text-lg">{group.subject}</h3>
                                    <div className="text-xs text-muted-foreground mt-1">{group.jid}</div>
                                    <div className="text-xs text-slate-500 mt-1">Participants: {group.participants?.length || 0}</div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </SessionGuard>
    );
}

