    return (
        <SessionProvider>
            <UpdateChecker />
            <div className="flex h-screen bg-background relative overflow-hidden">
                {/* Ambient Dashboard Background */}
                <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
