"use client";

import { useEffect, useState } from "react";
import SwaggerUI from "swagger-ui-react";
import "swagger-ui-react/swagger-ui.css";

export default function ApiDocsPage() {
    const [authorized, setAuthorized] = useState(false);
    const [loading, setLoading] = useState(true);
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState("");

    useEffect(() => {
        // Check if already authorized via session storage
        const isAuth = sessionStorage.getItem("swagger_auth") === "true";
        if (isAuth) {
            setAuthorized(true);
        }
        setLoading(false);
    }, []);

    const handleLogin = (e: React.FormEvent) => {
        e.preventDefault();

        // Basic auth - compare with env variables or hardcoded (for demo)
        const validUsername = process.env.NEXT_PUBLIC_SWAGGER_USERNAME || "admin";
        const validPassword = process.env.NEXT_PUBLIC_SWAGGER_PASSWORD || "admin123";

        if (username === validUsername && password === validPassword) {
            sessionStorage.setItem("swagger_auth", "true");
            setAuthorized(true);
            setError("");
        } else {
            setError("Invalid credentials");
        }
    };

    const handleLogout = () => {
        sessionStorage.removeItem("swagger_auth");
        setAuthorized(false);
        setUsername("");
        setPassword("");
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-gray-50">
                <div className="text-gray-600">Loading...</div>
            </div>
        );
    }

    if (!authorized) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
                <div className="bg-white p-8 rounded-lg shadow-xl w-full max-w-md">
                    <div className="text-center mb-6">
                        <h1 className="text-3xl font-bold text-gray-800 mb-2">
                            HAZA-WA API Documentation
                        </h1>
                        <p className="text-gray-600 text-sm">
                            Please authenticate to access Swagger UI
                        </p>
                    </div>

                    <form onSubmit={handleLogin} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Username
                            </label>
                            <input
                                type="text"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)}
                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                                placeholder="Enter username"
                                required
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Password
                            </label>
                            <input
                                type="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                                placeholder="Enter password"
                                required
                            />
                        </div>

                        {error && (
                            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg text-sm">
                                {error}
                            </div>
                        )}

                        <button
                            type="submit"
                            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-medium py-2 px-4 rounded-lg transition-colors"
                        >
                            Access Documentation
                        </button>
                    </form>

                    <div className="mt-6 text-center text-sm text-gray-500">
                        <p>Default credentials:</p>
                        <p className="font-mono mt-1">
                            Username: <span className="font-semibold">admin</span> |
                            Password: <span className="font-semibold">admin123</span>
                        </p>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-white">
            <div className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white p-4 shadow-lg">
                <div className="container mx-auto flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold">HAZA-WA API Documentation</h1>
                        <p className="text-blue-100 text-sm mt-1">
                            Interactive API documentation with 58+ endpoints
                        </p>
                    </div>
                    <button
                        onClick={handleLogout}
                        className="bg-white/20 hover:bg-white/30 px-4 py-2 rounded-lg transition-colors text-sm font-medium"
                    >
                        Logout
                    </button>
                </div>
            </div>

            <div className="container mx-auto">
                <SwaggerUI url="/api/docs" />
            </div>
        </div>
    );
}

import type { NextAuthConfig } from "next-auth";

export const authConfig = {
    pages: {
        signIn: '/auth/login',
    },
    callbacks: {
        authorized({ auth, request: { nextUrl } }) {
            const isLoggedIn = !!auth?.user;
            const isOnDashboard = nextUrl.pathname.startsWith('/dashboard');
            
            if (isOnDashboard) {
                if (isLoggedIn) return true;
                return false; // Redirect unauthenticated users to login page
            } else if (isLoggedIn && nextUrl.pathname === '/auth/login') {
                return Response.redirect(new URL('/dashboard', nextUrl));
            }
            return true;
        },
        async jwt({ token, user }) {
            if (user) {
                token.id = user.id;
                token.role = (user as any).role;
            }
            return token;
        },
        async session({ session, token }) {
            if (token && session.user) {
                session.user.id = token.id as string;
                (session.user as any).role = token.role;
            }
            return session;
        }
    },
    providers: [], // Configured in auth.ts
    session: {
        strategy: 'jwt'
    },
    trustHost: true,
} satisfies NextAuthConfig;

"use client";

import { useEffect, useState } from "react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { MessageSquarePlus } from "lucide-react";
import { Card } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";

import { cn } from "@/lib/utils";
import { io } from "socket.io-client";

interface ChatContact {
    jid: string;
    name: string | null;
    notify: string | null;
    profilePic: string | null;
    lastMessage?: {
        content: string | null;
        timestamp: string;
        type: string;
    }
}

interface ChatListProps {
    sessionId: string;
    onSelectChat: (jid: string, name?: string) => void;
    selectedJid?: string;
}

export function ChatList({ sessionId, onSelectChat, selectedJid }: ChatListProps) {
    const [chats, setChats] = useState<ChatContact[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchChats = async () => {
            try {
                const res = await fetch(`/api/chat/${sessionId}`);
                if (res.ok) {
                    const data = await res.json();
                    setChats(data);
                }
            } catch (error) {
                console.error("Failed to load chats", error);
            } finally {
                setLoading(false);
            }
        };

        if (sessionId) {
            fetchChats();

            const socket = io({
                path: "/api/socket/io",
                addTrailingSlash: false,
            });

            socket.on("connect", () => {
                socket.emit("join-session", sessionId);
            });

            socket.on("message.update", (newMessages: any[]) => {
                // We could optimise this by only updating the specific chat
                // But simplified: Update last message for existing chat OR Refetch if new chat

                setChats((prevChats) => {
                    let updatedChats = [...prevChats];
                    let needsReorder = false;

                    newMessages.forEach(msg => {
                        const chatIndex = updatedChats.findIndex(c => c.jid === msg.remoteJid);
                        if (chatIndex !== -1) {
                            // Update existing
                            updatedChats[chatIndex] = {
                                ...updatedChats[chatIndex],
                                lastMessage: {
                                    content: msg.content,
                                    timestamp: msg.timestamp,
                                    type: msg.type
                                }
                            };
                            needsReorder = true;
                        } else {
                            // New chat - fetch all again to get profile pic etc? 
                            // Or just optimistic add? 
                            // Let's refetch to be safe for now, or just ignore until user refresh 
                            fetchChats();
                        }
                    });

                    if (needsReorder) {
                        updatedChats.sort((a, b) => {
                            const tA = a.lastMessage?.timestamp ? new Date(a.lastMessage.timestamp).getTime() : 0;
                            const tB = b.lastMessage?.timestamp ? new Date(b.lastMessage.timestamp).getTime() : 0;
                            return tB - tA;
                        });
                    }

                    return updatedChats;
                });
            });

            return () => {
                socket.disconnect();
            };
        }
    }, [sessionId]);

    const [isNewChatOpen, setIsNewChatOpen] = useState(false);
    const [newChatNumber, setNewChatNumber] = useState("");

    if (loading) {
        return <div className="space-y-4">
            {[1, 2, 3].map(i => <Skeleton key={i} className="h-16 w-full" />)}
        </div>;
    }

    const handleStartNewChat = () => {
        if (!newChatNumber) return;
        // Basic cleaning
        let clean = newChatNumber.replace(/\D/g, '');
        if (clean.startsWith('0')) clean = '62' + clean.substring(1); // ID Auto-fix
        const jid = `${clean}@s.whatsapp.net`;
        onSelectChat(jid); // No name for new chats
        setIsNewChatOpen(false);
        setNewChatNumber("");
    };

    // Helper to get display name from contact
    const getContactDisplayName = (chat: ChatContact): string => {
        return chat.name || chat.notify || chat.jid.split('@')[0];
    };

    return (
        <div className="flex flex-col space-y-2">
            <div className="flex justify-between items-center mb-2 px-1">
                <h3 className="font-semibold text-lg">Chats</h3>
                <Button variant="outline" size="sm" onClick={() => setIsNewChatOpen(!isNewChatOpen)}>
                    <MessageSquarePlus className="h-4 w-4 mr-1" /> New
                </Button>
            </div>

            {isNewChatOpen && (
                <div className="p-3 bg-white border rounded-md shadow-sm mb-2 space-y-2">
                    <Label className="text-xs">Phone Number (e.g. 628...)</Label>
                    <div className="flex gap-2">
                        <Input
                            placeholder="628123456789"
                            value={newChatNumber}
                            onChange={(e) => setNewChatNumber(e.target.value)}
                            className="h-8"
                        />
                        <Button size="sm" onClick={handleStartNewChat}>Go</Button>
                    </div>
                </div>
            )}

            <div className="overflow-y-auto h-[calc(100vh-200px)] space-y-2">
                {chats.map((chat) => {
                    const displayName = getContactDisplayName(chat);
                    return (
                        <Card
                            key={chat.jid}
                            className={cn(
                                "p-3 cursor-pointer hover:bg-slate-50 transition-colors flex items-center gap-3",
                                selectedJid === chat.jid && "bg-slate-100 border-primary"
                            )}
                            onClick={() => onSelectChat(chat.jid, displayName)}
                        >
                            <Avatar>
                                <AvatarImage src={chat.profilePic || ""} />
                                <AvatarFallback>{displayName.slice(0, 2).toUpperCase()}</AvatarFallback>
                            </Avatar>
                            <div className="flex-1 min-w-0">
                                <div className="flex justify-between items-center mb-1">
                                    <h4 className="font-semibold text-sm truncate">{displayName}</h4>
                                    {chat.lastMessage && (
                                        <span className="text-xs text-muted-foreground whitespace-nowrap ml-2">
                                            {new Date(chat.lastMessage.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        </span>
                                    )}
                                </div>
                                <p className="text-xs text-muted-foreground block w-full truncate">
                                    {chat.lastMessage?.content
                                        ? chat.lastMessage.content.length > 15
                                            ? chat.lastMessage.content.slice(0, 15) + "..."
                                            : chat.lastMessage.content
                                        : "No messages"}

                                </p>
                            </div>
                        </Card>
                    );
                })}
            </div>
            {chats.length === 0 && (
                <div className="text-center text-muted-foreground py-8">
                    No chats found.
                </div>
            )}
        </div>
    );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Send, Paperclip } from "lucide-react";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Image as ImageIcon, FileText, Music, Sticker as StickerIcon, Video, AlertCircle } from "lucide-react";
import { cn } from "@/lib/utils";
import { io, Socket } from "socket.io-client";
import { toast } from "sonner";

interface Message {
    keyId: string;
    content: string;
    fromMe: boolean;
    timestamp: string;
    type: string;
    status: string;
    pushName?: string;
    mediaUrl?: string;
    remoteJid?: string;
}

interface ChatWindowProps {
    sessionId: string;
    jid: string;
    name?: string;
}

export function ChatWindow({ sessionId, jid, name }: ChatWindowProps) {
    const [messages, setMessages] = useState<Message[]>([]);
    const [newMessage, setNewMessage] = useState("");
    const scrollRef = useRef<HTMLDivElement>(null);
    const [socket, setSocket] = useState<Socket | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [uploadType, setUploadType] = useState<string>("image");

    // Scroll to bottom helper
    const scrollToBottom = (smooth = true) => {
        if (scrollRef.current) {
            scrollRef.current.scrollIntoView({ behavior: smooth ? "smooth" : "auto", block: "end" });
        }
    };

    // Auto-scroll on messages change
    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const fetchMessages = async () => {
        try {
            const res = await fetch(`/api/chat/${sessionId}/${encodeURIComponent(jid)}`);
            if (res.ok) {
                const data = await res.json();
                setMessages(data);
                // Force scroll buffer
                setTimeout(() => scrollToBottom(false), 100);
            }
        } catch (error) {
            console.error("Failed to load messages", error);
        }
    }



    useEffect(() => {
        // Initial Fetch
        fetchMessages();

        // Socket Connection
        const newSocket = io({
            path: "/api/socket/io",
            addTrailingSlash: false,
        });

        newSocket.on("connect", () => {
            console.log("Connected to socket");
            newSocket.emit("join-session", sessionId);
        });

        newSocket.on("message.update", (newMessages: Message[]) => {
            setMessages((prev) => {
                // De-duplicate and sort
                const combined = [...prev, ...newMessages.filter(m => m.remoteJid === jid)];
                const unique = Array.from(new Map(combined.map(m => [m.keyId, m])).values());
                return unique.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
            });
            // Scroll will happen via the [messages] dependency
        });

        setSocket(newSocket);

        return () => {
            newSocket.disconnect();
        };
    }, [sessionId, jid]);

    const handleSend = async () => {
        if (!newMessage.trim()) return;

        try {
            await fetch(`/api/chat/send`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    sessionId,
                    jid,
                    message: { text: newMessage }
                })
            });
            setNewMessage("");
            fetchMessages(); // Refresh immediately
        } catch (e) {
            console.error(e);
        }
    };

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const formData = new FormData();
        formData.append("file", file);
        formData.append("type", uploadType);
        // formData.append("caption", newMessage); // Optional: Send current text as caption

        try {
            toast.info("Sending...");
            const res = await fetch(`/api/messages/${sessionId}/${encodeURIComponent(jid)}/media`, {
                method: "POST",
                body: formData
            });

            if (!res.ok) throw new Error("Failed to send media");
            toast.success("Sent!");
            // Socket will handle update
        } catch (error) {
            console.error(error);
            toast.error("Failed to send media");
        } finally {
            if (fileInputRef.current) fileInputRef.current.value = "";
        }
    };

    const triggerUpload = (type: string) => {
        setUploadType(type);
        if (fileInputRef.current) {
            fileInputRef.current.accept = type === 'image' ? "image/*" : type === 'video' ? "video/*" : type === 'audio' ? "audio/*" : type === 'sticker' ? "image/*" : "*/*";
            // For sticker, we accept image to convert
            fileInputRef.current.click();
        }
    };

    return (
        <div className="flex flex-col h-full bg-slate-50">
            {/* Header */}
            <div className="p-4 border-b bg-white flex items-center space-x-3 shadow-sm">
                <Avatar>
                    <AvatarFallback>{(name || jid).slice(0, 2).toUpperCase()}</AvatarFallback>
                </Avatar>
                <div>
                    <h3 className="font-semibold">{name || jid}</h3>
                    <span className="text-xs text-muted-foreground">{jid}</span>
                </div>
            </div>

            {/* Messages Area */}
            <ScrollArea className="flex-1 min-h-0 p-4">
                <div className="space-y-4 pb-4">
                    {messages.map((msg) => (
                        <div
                            key={msg.keyId}
                            className={cn(
                                "flex w-fit max-w-[75%] flex-col gap-1 rounded-lg px-3 py-2 text-sm shadow-sm break-words whitespace-pre-wrap",
                                msg.fromMe
                                    ? "ml-auto bg-primary text-primary-foreground"
                                    : "bg-white border"
                            )}
                        >
                            {/* Sender Name (for received messages in groups) */}
                            {!msg.fromMe && msg.pushName && (
                                <span className="text-[10px] font-bold text-orange-600 mb-0.5">
                                    {msg.pushName}
                                </span>
                            )}

                            {msg.type === 'IMAGE' && msg.mediaUrl && (
                                <img src={msg.mediaUrl} alt="Image" className="rounded-md max-h-64 object-cover mb-1" />
                            )}
                            {msg.type === 'STICKER' && msg.mediaUrl && (
                                <img src={msg.mediaUrl} alt="Sticker" className="rounded-md max-h-32 object-contain mb-1" />
                            )}
                            {/* Simple fallback for other media */}
                            {msg.type !== 'TEXT' && msg.type !== 'IMAGE' && msg.type !== 'STICKER' && (
                                <div className="flex items-center gap-2 p-2 bg-black/10 rounded">
                                    <FileText className="h-4 w-4" />
                                    <span className="text-xs italic">{msg.type} Message</span>
                                </div>
                            )}

                            {msg.content}
                            <span className={cn("text-[10px] self-end opacity-70", msg.fromMe ? "text-primary-foreground" : "text-muted-foreground")}>
                                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </span>
                        </div>
                    ))}
                    <div ref={scrollRef} />
                </div>
            </ScrollArea>

            {/* Input Area */}
            <div className="p-4 bg-white border-t flex items-center gap-2">
                <input
                    type="file"
                    ref={fileInputRef}
                    className="hidden"
                    onChange={handleFileUpload}
                />
                <Popover>
                    <PopoverTrigger asChild>
                        <Button variant="ghost" size="icon">
                            <Paperclip className="h-5 w-5 text-muted-foreground" />
                        </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-48 p-2" side="top" align="start">
                        <div className="flex flex-col gap-1">
                            <Button variant="ghost" size="sm" className="justify-start gap-2" onClick={() => triggerUpload('image')}>
                                <ImageIcon className="h-4 w-4" /> Image
                            </Button>
                            <Button variant="ghost" size="sm" className="justify-start gap-2" onClick={() => triggerUpload('video')}>
                                <Video className="h-4 w-4" /> Video
                            </Button>
                            <Button variant="ghost" size="sm" className="justify-start gap-2" onClick={() => triggerUpload('audio')}>
                                <Music className="h-4 w-4" /> Audio
                            </Button>
                            <Button variant="ghost" size="sm" className="justify-start gap-2" onClick={() => triggerUpload('document')}>
                                <FileText className="h-4 w-4" /> Document
                            </Button>
                            <Button variant="ghost" size="sm" className="justify-start gap-2" onClick={() => triggerUpload('sticker')}>
                                <StickerIcon className="h-4 w-4" /> Sticker
                            </Button>
                        </div>
                    </PopoverContent>
                </Popover>
                <Input
                    placeholder="Type a message..."
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && handleSend()}
                    className="flex-1"
                />
                <Button onClick={handleSend} disabled={!newMessage.trim()}>
                    <Send className="h-4 w-4" />
                </Button>
            </div>
        </div>
    )
}

