export function SidebarNav() {
    const pathname = usePathname();
    const { data: session } = useSession();
    // @ts-ignore
    const userRole = session?.user?.role;

    // Track collapsed groups ΓÇö all expanded by default
    const [collapsed, setCollapsed] = useState<Record<string, boolean>>({});

    const toggleGroup = (label: string) => {
        setCollapsed(prev => ({ ...prev, [label]: !prev[label] }));
    };

    const isActive = (href: string) => {
        if (href === "/dashboard") return pathname === "/dashboard";
        return pathname.startsWith(href);
    };

    return (
        <nav className="flex-1 px-3 py-2 overflow-y-auto space-y-1">
            {navGroups.map((group) => {
                const visibleItems = group.items.filter(
                    (item) => !item.superadminOnly || userRole === "SUPERADMIN"
                );
                if (visibleItems.length === 0) return null;

                const isCollapsed = collapsed[group.label] ?? false;

                // "Main" group doesn't show a collapsible header
                if (group.label === "Main") {
                    return (
                        <div key={group.label} className="mb-1">
                            {visibleItems.map((item) => (
                                <NavLink
                                    key={item.href}
                                    item={item}
                                    active={isActive(item.href)}
                                />
                            ))}
                        </div>
                    );
                }

                return (
                    <div key={group.label} className="mb-2">
                        <button
                            onClick={() => toggleGroup(group.label)}
                            className="flex items-center justify-between w-full px-4 py-2 text-[11px] font-bold uppercase tracking-widest text-muted-foreground/70 hover:text-foreground transition-colors group"
                        >
                            {group.label}
                            <ChevronDown
                                size={14}
                                className={`transition-transform duration-300 ease-out group-hover:text-primary ${isCollapsed ? "-rotate-90" : ""}`}
                            />
                        </button>
                        {!isCollapsed && (
                            <div className="space-y-1 mt-1">
                                {visibleItems.map((item) => (
                                    <NavLink
                                        key={item.href}
                                        item={item}
                                        active={isActive(item.href)}
                                    />
                                ))}
                            </div>
                        )}
                    </div>
                );
            })}
        </nav>
    );
}

function NavLink({ item, active }: { item: NavItem; active: boolean }) {
    const Icon = item.icon;
    return (
        <Link
            href={item.href}
            target={item.external ? "_blank" : undefined}
            className={`
                flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium
                transition-all duration-300 ease-out group relative overflow-hidden
                ${active
                    ? "text-primary bg-primary/10 shadow-sm border border-primary/20"
                    : "text-muted-foreground hover:bg-muted/50 hover:text-foreground border border-transparent"
                }
            `}
        >
            {active && (
                <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-primary rounded-r-full shadow-[0_0_10px_rgba(var(--color-primary),0.5)]" />
            )}
            <Icon
                size={18}
                className={`flex-shrink-0 transition-all duration-300 ${active ? "text-primary scale-110" : "text-muted-foreground/70 group-hover:text-foreground group-hover:scale-110"}`}
            />
            <span className="truncate">{item.label}</span>
        </Link>
    );
}

import { prisma } from "./prisma";
import crypto from "crypto";
import { normalizeMessageContent, downloadMediaMessage, WAMessage } from "@whiskeysockets/baileys";
import { writeFile, mkdir } from "fs/promises";
import path from "path";
import pino from "pino";

// Event types that can trigger webhooks
export type WebhookEventType = 
    | "message.received"
    | "message.sent"
    | "message.status"
    | "connection.update"
    | "group.update"
    | "contact.update"
    | "status.update";

interface WebhookPayload {
    event: WebhookEventType;
    sessionId: string;
    timestamp: string;
    data: any;
}

/**
 * Dispatch webhook to all matching endpoints
 */
export async function dispatchWebhook(
    sessionId: string, 
    event: WebhookEventType, 
    data: any
) {
    try {
        // Get the session to find the userId
        const session = await prisma.session.findUnique({
            where: { sessionId },
            select: { id: true, userId: true }
        });

        if (!session) {
            console.warn(`Webhook dispatch: Session ${sessionId} not found`);
            return;
        }

        // Find all active webhooks for this user/session
        const webhooks = await prisma.webhook.findMany({
            where: {
                userId: session.userId,
                isActive: true,
                OR: [
                    { sessionId: null }, // Global webhooks
                    { sessionId: session.id } // Session-specific webhooks
                ]
            }
        });

        if (webhooks.length === 0) return;

        const payload: WebhookPayload = {
            event,
            sessionId,
            timestamp: new Date().toISOString(),
            data: normalizePayloadData(event, data) // Normalize data before sending
        };

        // Dispatch to all matching webhooks
        for (const webhook of webhooks) {
            // Check if this webhook subscribes to this event
            const events = (webhook.events as string[]) || [];
            if (!events.includes(event) && !events.includes("*")) {
                continue;
            }

            // Send webhook in background
            sendWebhookRequest(webhook.url, payload, webhook.secret).catch(err => {
                console.error(`Webhook ${webhook.id} failed:`, err);
            });
        }
    } catch (error) {
        console.error("Webhook dispatch error:", error);
    }
}

/**
 * Normalize payload data to match API format and avoid Circular/BigInt errors
 */
function normalizePayloadData(event: WebhookEventType, data: any): any {
    if (event === "message.received" || event === "message.sent") {
        // If data is already simplified, return it
        if (data.type && data.content) return data;

        // If data is raw Baileys message (which we shouldn't be passing raw anymore, but just in case)
        // Ideally the caller (onMessageReceived) should have already simplified it.
        // But let's handle the specific fields passed by onMessageReceived below.
        return data; 
    }
    return data;
}

/**
 * JSON Replacer to handle BigInt
 */
function jsonReplacer(key: string, value: any) {
    if (typeof value === 'bigint') {
        return value.toString();
    }
    return value;
}

/**
 * Send HTTP POST request to webhook endpoint
 */
async function sendWebhookRequest(url: string, payload: WebhookPayload, secret?: string | null) {
    // Use custom replacer for BigInt support
    const body = JSON.stringify(payload, jsonReplacer);
    
    const headers: Record<string, string> = {
        "Content-Type": "application/json",
        "User-Agent": "HAZA-WA-Webhook/1.0"
    };

    // Add HMAC signature if secret is provided
    if (secret) {
        const signature = crypto
            .createHmac("sha256", secret)
            .update(body)
            .digest("hex");
        headers["X-Webhook-Signature"] = `sha256=${signature}`;
    }

    const response = await fetch(url, {
        method: "POST",
        headers,
        body,
        signal: AbortSignal.timeout(10000) // 10 second timeout
    });

    if (!response.ok) {
        throw new Error(`Webhook returned ${response.status}: ${response.statusText}`);
    }

    return response;
}

/**
 * Helper to download and save media
 */
export async function downloadAndSaveMedia(message: WAMessage, sessionId: string): Promise<string | null> {
    try {
        const messageContent = normalizeMessageContent(message.message);
        if (!messageContent) {
            console.log("MediaDownload: No content normalized");
            return null;
        }

        const messageType = Object.keys(messageContent)[0];
        console.log(`MediaDownload: Types checking... Found: ${messageType}`);

        if (!['imageMessage', 'videoMessage', 'audioMessage', 'documentMessage', 'stickerMessage'].includes(messageType)) {
             console.log(`MediaDownload: Message type ${messageType} is not a downloadable media.`);
            return null;
        }
        
        console.log(`MediaDownload: Attempting to download ${messageType}...`);

        const buffer = await downloadMediaMessage(
            message,
            "buffer",
            {}
        ) as Buffer;

        if (!buffer) {
             console.log("MediaDownload: Buffer is empty/null");
             return null;
        }
        
        console.log(`MediaDownload: Downloaded ${buffer.length} bytes.`);

        // Generate filename
        const extMap: Record<string, string> = {
            imageMessage: 'jpg',
            videoMessage: 'mp4',
            audioMessage: 'mp3',
            documentMessage: 'bin',
            stickerMessage: 'webp'
        };
        
        let ext = extMap[messageType] || 'bin';
        
        // Try to get extension from mimetype if available
        const mime = (messageContent as any)[messageType]?.mimetype;
        if (mime) {
            const mimeExt = mime.split('/')[1]?.split(';')[0];
            if (mimeExt) ext = mimeExt;
        }

        const filename = `${sessionId}-${message.key.id}.${ext}`;
        const filePath = path.join(process.cwd(), "public", "media", filename);

        console.log(`MediaDownload: Saving to ${filePath}`);

        // Ensure directory exists (redundant if handled by OS, but safe)
        await mkdir(path.dirname(filePath), { recursive: true });
        
        await writeFile(filePath, buffer);
        
        // Return URL path using API route for reliable serving
        const fileUrl = `/api/media/${filename}`;
        console.log(`MediaDownload: Success. URL: ${fileUrl}`);
        return fileUrl;

    } catch (e) {
        console.error("Failed to download media:", e);
        return null;
    }
}

/**
 * Helper to dispatch message received event
 * Normalizes message content to match API structure
 */
export async function onMessageReceived(sessionId: string, message: any, existingFileUrl?: string | null) {
    // Re-calculate fields to match store logic EXACTLY
    const remoteJid = message.key?.remoteJid || "";
    const fromMe = message.key?.fromMe || false;
    const isGroup = remoteJid.endsWith("@g.us");
    const participant = isGroup ? (message.key?.participant || message.participant) : undefined;
    
    // Extract Alt JID (e.g. Phone Number JID when remoteJid is LID)
    // Note: Baileys puts this in key sometimes
    const remoteJidAlt = message.key?.remoteJidAlt || null;

    // "from" is usually the chat JID (remoteJid)
    // "sender" is who sent it. In DM: remoteJid. In Group: participant.
    // If DM and remoteJidAlt exists (Phone JID), user prefers that as sender.
    let sender: any = isGroup ? participant : remoteJid;
    if (!isGroup && remoteJidAlt) {
        sender = remoteJidAlt;
    }
    
    // Enrich Participant Data if Group
    let participantDetail: any = participant;
    
    if (isGroup && typeof sender === 'string') {
        try {
            // Need dbSessionId
            const session = await prisma.session.findUnique({ 
                where: { sessionId },
                select: { id: true }
            });
            
            if (session) {
                const group = await prisma.group.findUnique({
                    where: { 
                        sessionId_jid: { 
                            sessionId: session.id, 
                            jid: remoteJid 
                        } 
                    },
                    select: { participants: true }
                });
                
                if (group && group.participants) {
                    const parts = group.participants as any[];
                    // Try to match sender or participant JID
                    const found = parts.find(p => p.id === sender || p.id === participant);
                    if (found) {
                        sender = found;
                        participantDetail = found;
                    }
                }
            }
        } catch (e) {
            console.error("Failed to enrich participant", e);
        }
    }

    // Download media if available (or use existing)
    let fileUrl: string | null = existingFileUrl || null;
    if (!fileUrl) {
        try {
            fileUrl = await downloadAndSaveMedia(message, sessionId);
        } catch (e) {
             console.error("Error handling media download", e);
        }
    }

    const normalized = extractMessageContent(message);
    const quoted = await extractQuotedMessageAsync(message, sessionId); // Extract quoted message (async now)
    
    dispatchWebhook(sessionId, "message.received", {
        key: {
            id: message.key?.id,
            remoteJid: remoteJid,
            fromMe: fromMe,
            participant: participantDetail
        },
        pushName: message.pushName,
        messageTimestamp: message.messageTimestamp,
        
        // Simplified Fields
        from: remoteJid,            // Chat ID
        sender: sender,             // Who Sent It (Preferred JID or Object)
        remoteJidAlt: remoteJidAlt, // Explicit Alt Field
        isGroup: isGroup,           // Boolean
        
        // Message Content
        type: normalized.type,
        content: normalized.content,
        fileUrl: fileUrl,           // Link to file if media
        caption: normalized.caption, // Separate caption
        quoted: quoted,             // Quoted Message Details
        
        // Raw Data (Requested by User)
        raw: message
    });
}

/**
 * Helper to dispatch message sent event
 */
export async function onMessageSent(sessionId: string, message: any, existingFileUrl?: string | null) {
    const normalized = extractMessageContent(message);
    const quoted = await extractQuotedMessageAsync(message, sessionId); // Extract quoted message
    const remoteJid = message.key?.remoteJid || "";
    
    // Download media for sent messages too (optional but good)
    let fileUrl: string | null = existingFileUrl || null;
    if (!fileUrl) {
        try {
            fileUrl = await downloadAndSaveMedia(message, sessionId);
        } catch (e) { /* ignore */ }
    }
    
    // For sent messages, sender is always ME (or represented by the bot)
    // If it's a group, the participant might be undefined in the key if sent by us, 
    // but typically we are the sender.
    const sender = message.key?.participant || (message.key?.fromMe ? "ME" : remoteJid);
    const remoteJidAlt = message.key?.remoteJidAlt || null;

    dispatchWebhook(sessionId, "message.sent", {
        key: message.key,
        
        from: remoteJid,
        sender: sender,
        remoteJidAlt: remoteJidAlt, 
        isGroup: remoteJid.endsWith("@g.us"),
        
        type: normalized.type,
        content: normalized.content,
        fileUrl: fileUrl,
        caption: normalized.caption,
        quoted: quoted,
        
        timestamp: Date.now(),
        raw: message
    });
}

/**
 * Determine chat type from JID
 */
function getChatType(jid: string): "PERSONAL" | "GROUP" | "STATUS" | "NEWSLETTER" | "UNKNOWN" {
    if (!jid) return "UNKNOWN";
    if (jid.endsWith("@g.us")) return "GROUP";
    if (jid.endsWith("@s.whatsapp.net")) return "PERSONAL";
    if (jid === "status@broadcast") return "STATUS";
    if (jid.endsWith("@newsletter")) return "NEWSLETTER";
    return "UNKNOWN";
}

/**
 * Helper to dispatch connection update event
 */
export function onConnectionUpdate(sessionId: string, status: string, qr?: string) {
    dispatchWebhook(sessionId, "connection.update", {
        status,
        qr: qr || null
    });
}

/**
 * Extract content and type from Baileys message
 */
function extractMessageContent(msg: any): { type: string, content: string, caption?: string } {
    const messageContent = normalizeMessageContent(msg.message);
    let text = "";
    let caption = undefined;
    let messageType = "TEXT";

    if (!messageContent) return { type: "UNKNOWN", content: "" };

    if (messageContent.conversation) {
        text = messageContent.conversation;
    } else if (messageContent.extendedTextMessage?.text) {
        text = messageContent.extendedTextMessage.text;
    } else if (messageContent.imageMessage) {
        messageType = "IMAGE";
        caption = messageContent.imageMessage.caption || "";
        text = caption; // Content often used as text display
    } else if (messageContent.videoMessage) {
        messageType = "VIDEO";
        caption = messageContent.videoMessage.caption || "";
        text = caption;
    } else if (messageContent.audioMessage) {
        messageType = "AUDIO";
    } else if (messageContent.documentMessage) {
        messageType = "DOCUMENT";
        text = messageContent.documentMessage.fileName || "";
        caption = messageContent.documentMessage.caption || "";
    } else if (messageContent.stickerMessage) {
        messageType = "STICKER";
    } else if (messageContent.locationMessage) {
        messageType = "LOCATION";
        text = `${messageContent.locationMessage.degreesLatitude},${messageContent.locationMessage.degreesLongitude}`;
    } else if (messageContent.contactMessage) {
        messageType = "CONTACT";
        text = messageContent.contactMessage.displayName || "";
    }

    return { type: messageType, content: text, caption };
}



/**
 * Extract Quoted Message recursively (Async to Lookup DB)
 */
async function extractQuotedMessageAsync(msg: any, sessionId: string): Promise<any> {
    const messageContent = normalizeMessageContent(msg.message);
    if (!messageContent) return null;
    
    // Check for contextInfo in common message types
    let contextInfo: any = null;
    
    if (messageContent.extendedTextMessage) {
        contextInfo = messageContent.extendedTextMessage.contextInfo;
    } else if (messageContent.imageMessage) {
        contextInfo = messageContent.imageMessage.contextInfo;
    } else if (messageContent.videoMessage) {
        contextInfo = messageContent.videoMessage.contextInfo;
    } else if (messageContent.audioMessage) {
        contextInfo = messageContent.audioMessage.contextInfo;
    } else if (messageContent.stickerMessage) {
        contextInfo = messageContent.stickerMessage.contextInfo;
    } else if (messageContent.documentMessage) {
        contextInfo = messageContent.documentMessage.contextInfo;
    } else if (messageContent.contactMessage) {
         contextInfo = messageContent.contactMessage.contextInfo;
    } else if (messageContent.locationMessage) {
         contextInfo = messageContent.locationMessage.contextInfo;
    }

    if (contextInfo && contextInfo.quotedMessage) {
        const quotedMsg = contextInfo.quotedMessage;
        const normalized = extractMessageContent({ message: quotedMsg });
        
        let fileUrl = null;
        
        // Lookup Media URL in DB if possible
        if (contextInfo.stanzaId) {
            try {
                // We need the dbSessionId... this is tricky without fetching session again.
                // But we can try to look up by sessionId (baileys ID) and keyId
                // Message table has @@unique([sessionId, keyId]). BUT sessionId there is the CUID, not the string.
                
                // Fetch CUID First
                 const session = await prisma.session.findUnique({
                    where: { sessionId },
                    select: { id: true }
                });
                
                if (session) {
                    const savedMsg = await prisma.message.findUnique({
                        where: {
                            sessionId_keyId: {
                                sessionId: session.id,
                                keyId: contextInfo.stanzaId
                            }
                        },
                        select: { mediaUrl: true }
                    });
                    
                    if (savedMsg?.mediaUrl) {
                        fileUrl = savedMsg.mediaUrl;
                    }
                }
            } catch (e) {
                console.error("Failed to lookup quoted media url", e);
            }
        }
        
        return {
            key: {
                remoteJid: contextInfo.remoteJid || null, // Group JID
                participant: contextInfo.participant || null, // Sender JID
                fromMe: contextInfo.participant === undefined, // Not reliable, better check participant
                id: contextInfo.stanzaId || null
            },
            type: normalized.type,
            content: normalized.content, // Text or Caption
            caption: normalized.caption,
            fileUrl: fileUrl, // <--- Added!
            // We don't download quoted media automatically unless it was already saved
            // raw: quotedMsg 
        };
    }
    
    return null;
}

import { prisma } from "@/lib/prisma";
import { AuthenticationCreds, AuthenticationState, BufferJSON, initAuthCreds, SignalDataTypeMap } from "@whiskeysockets/baileys";

export const usePrismaAuthState = async (sessionId: string): Promise<{ state: AuthenticationState, saveCreds: () => Promise<void> }> => {
    
    // Helper to read JSON with Buffer handling
    const readData = async (type: string, id: string) => {
        try {
            const key = `${type}-${id}`;
            const data = await prisma.authState.findUnique({
                where: { sessionId_key: { sessionId, key } }
            });
            if (data && data.value) {
                return JSON.parse(JSON.stringify(data.value), BufferJSON.reviver);
            }
            return null;
        } catch (error) {
            console.error('Error reading auth state:', error);
            return null;
        }
    };

    // Helper to write data
    const writeData = async (type: string, id: string, data: any) => {
        try {
            const key = `${type}-${id}`;
            const value = JSON.parse(JSON.stringify(data, BufferJSON.replacer));
            
            await prisma.authState.upsert({
                where: { sessionId_key: { sessionId, key } },
                create: { sessionId, key, value },
                update: { value }
            });
        } catch (error) {
             console.error('Error writing auth state:', error);
        }
    };

    const removeData = async (type: string, id: string) => {
        try {
            const key = `${type}-${id}`;
             await prisma.authState.deleteMany({
                where: { sessionId, key }
            });
        } catch (error) {
            // ignore
        }
    }


    const creds: AuthenticationCreds = (await readData('creds', 'me')) || initAuthCreds();

    return {
        state: {
            creds,
            keys: {
                get: async (type, ids) => {
                    const data: { [key: string]: SignalDataTypeMap[typeof type] } = {};
                    await Promise.all(ids.map(async id => {
                        let value = await readData(type, id);
                        if (type === 'app-state-sync-key' && value) {
                            value = BufferJSON.reviver(null, value);
                        }
                        if (value) {
                            data[id] = value;
                        }
                    }));
                    return data;
                },
                set: async (data) => {
                     const tasks: Promise<void>[] = [];
                    for (const category in data) {
                        const categoryData = data[category as keyof typeof data];
                        if (!categoryData) continue;
                        
                        for (const id in categoryData) {
                            const value = categoryData[id];
                             if (value) {
                                tasks.push(writeData(category, id, value));
                            } else {
                                tasks.push(removeData(category, id));
                            }
                        }
                    }
                    await Promise.all(tasks);
                }
            }
        },
        saveCreds: async () => {
            await writeData('creds', 'me', creds);
        }
    }
}

import { prisma } from "@/lib/prisma";
import type { WASocket, WAMessage } from "@whiskeysockets/baileys";
import { downloadMediaMessage } from "@whiskeysockets/baileys";
import Sticker from "wa-sticker-formatter";
import sharp from "sharp";
import fs from "fs/promises";
import path from "path";
import os from "os";
import { exec } from "child_process";
import { promisify } from "util";

const execAsync = promisify(exec);

// Map to track start times for uptime
const startTimes = new Map<string, number>();

// Default bot config
// Default bot config
const DEFAULT_CONFIG = {
    enabled: true,
    botMode: 'OWNER',
    botAllowedJids: [] as string[],
    autoReplyMode: 'ALL',
    autoReplyAllowedJids: [] as string[],
    enableSticker: true,
    enableVideoSticker: true,
    maxStickerDuration: 10,
    enablePing: true,
    enableUptime: true,
    botName: "HAZA-WA Bot",
    removeBgApiKey: null as string | null
};

export function setSessionStartTime(sessionId: string) {
    if (!startTimes.has(sessionId)) {
        startTimes.set(sessionId, Date.now());
    }
}

export async function handleBotCommand(
    sock: WASocket | undefined,
    sessionId: string,
    msg: WAMessage
) {
    if (!sock || !msg.message || !msg.key.remoteJid) return;

    const remoteJid = msg.key.remoteJid;
    const fromMe = msg.key.fromMe || false;

    // Get text content
    let text = "";
    const messageContent = msg.message;

    if (messageContent.conversation) {
        text = messageContent.conversation;
    } else if (messageContent.extendedTextMessage?.text) {
        text = messageContent.extendedTextMessage.text;
    } else if (messageContent.imageMessage?.caption) {
        text = messageContent.imageMessage.caption;
    } else if (messageContent.videoMessage?.caption) {
        text = messageContent.videoMessage.caption;
    }

    if (!text.startsWith("#")) return;

    // Fetch session first
    const session = await prisma.session.findUnique({
        where: { sessionId },
        select: { id: true }
    });

    if (!session) return;

    // Fetch BotConfig separately
    // @ts-ignore - Prisma Client types might lag in IDE
    const botConfig = await (prisma as any).botConfig.findUnique({
        where: { sessionId: session.id }
    });

    const config = botConfig || DEFAULT_CONFIG;

    if (!config.enabled) return;

    // Verify Access Permissions
    const botMode = (config as any).botMode || 'OWNER'; // Default to OWNER if missing

    // Check Permission
    let canExecute = false;

    if (fromMe) {
        canExecute = true; // Owner always allowed
    } else {
        if (botMode === 'ALL') {
            canExecute = true;
        } else if (botMode === 'SPECIFIC') {
            const allowedJids = (config as any).botAllowedJids || [];
            // Standardized Sender Logic (matches webhook & store)
            const isGroup = msg.key.remoteJid?.endsWith("@g.us") || false;
            const remoteJidAlt = msg.key.remoteJidAlt;
            let senderJid = (isGroup ? (msg.key.participant || msg.participant) : msg.key.remoteJid) || "";

            if (!isGroup && remoteJidAlt) {
                senderJid = remoteJidAlt;
            }

            if (Array.isArray(allowedJids)) {
                canExecute = allowedJids.some(jid => senderJid.includes(jid));
            }
        } else if (botMode === 'BLACKLIST') {
            const blockedJids = (config as any).botBlockedJids || [];
            const isGroup = msg.key.remoteJid?.endsWith("@g.us") || false;
            const remoteJidAlt = msg.key.remoteJidAlt;
            let senderJid = (isGroup ? (msg.key.participant || msg.participant) : msg.key.remoteJid) || "";

            if (!isGroup && remoteJidAlt) {
                senderJid = remoteJidAlt;
            }

            // If blacklist, allowed by default UNLESS in blocked list
            canExecute = true;
            if (Array.isArray(blockedJids)) {
                const isBlocked = blockedJids.some(jid => senderJid.includes(jid));
                if (isBlocked) canExecute = false;
            }
        }
    }

    if (!canExecute) return;

    const [command, ...args] = text.trim().split(" ");
    const cmd = command.toLowerCase().slice(1); // remove #

    try {
        switch (cmd) {
            case "ping": {
                if (!config.enablePing) return;
                await sock.sendMessage(remoteJid, { text: "Pong! ≡ƒÅô" }, { quoted: msg });
                break;
            }

            case "id": {
                await sock.sendMessage(remoteJid, {
                    text: `*Chat ID:* \`${remoteJid}\``
                }, { quoted: msg });
                break;
            }

            case "uptime": {
                if (!config.enableUptime) return;

                const start = startTimes.get(sessionId) || Date.now();
                const uptimeMs = Date.now() - start;
                const hours = Math.floor(uptimeMs / 3600000);
                const minutes = Math.floor((uptimeMs % 3600000) / 60000);
                const seconds = Math.floor((uptimeMs % 60000) / 1000);

                await sock.sendMessage(remoteJid, {
                    text: `*Session Uptime:* ${hours}h ${minutes}m ${seconds}s`
                }, { quoted: msg });
                break;
            }

            case "sticker":
            case "s":
            case "stiker": {
                if (!config.enableSticker) return;

                // Check if message has image or video
                let mediaMsg: WAMessage | null = msg;

                // If quoted, check quoted
                const quoted = messageContent.extendedTextMessage?.contextInfo?.quotedMessage;
                if (quoted) {
                    mediaMsg = {
                        key: {
                            remoteJid,
                            id: messageContent.extendedTextMessage?.contextInfo?.stanzaId,
                        },
                        message: quoted
                    } as WAMessage;
                }

                const msgContent = mediaMsg.message;
                const isImage = !!msgContent?.imageMessage;
                const isVideo = !!msgContent?.videoMessage;

                if (!isImage && !isVideo) {
                    await sock.sendMessage(remoteJid, { text: "Γ¥î Please reply to an image/video or send media with caption #sticker" }, { quoted: msg });
                    return;
                }

                if (msgContent?.extendedTextMessage) {
                    await sock.sendMessage(remoteJid, { text: "Γ¥î Cannot convert text message to sticker." }, { quoted: msg });
                    return;
                }

                // Handle Video Limits
                if (isVideo) {
                    if (!(config as any).enableVideoSticker) {
                        await sock.sendMessage(remoteJid, { text: "Γ¥î Video stickers are disabled in bot settings." }, { quoted: msg });
                        return;
                    }

                    const seconds = msgContent?.videoMessage?.seconds || 0;
                    const maxDuration = (config as any).maxStickerDuration || 10;

                    if (seconds > maxDuration) {
                        await sock.sendMessage(remoteJid, { text: `Γ¥î Video too long! Max duration is ${maxDuration} seconds.` }, { quoted: msg });
                        return;
                    }
                }

                await sock.sendMessage(remoteJid, { react: { text: "ΓÅ│", key: msg.key } });

                try {
                    // Download
                    let buffer = await downloadMediaMessage(
                        mediaMsg,
                        "buffer",
                        {},
                        {
                            logger: console as any,
                            reuploadRequest: sock.updateMediaMessage
                        }
                    ) as Buffer;

                    // Resize/Compress Logic
                    if (isImage) {
                        try {
                            // Use limitInputPixels: false to handle large images
                            buffer = await sharp(buffer, { limitInputPixels: false })
                                .resize(512, 512, { // Resize to standard 512x512 sticker size directly
                                    fit: 'inside',
                                    withoutEnlargement: true
                                })
                                .toBuffer();
                        } catch (resizeErr) {
                            console.error("Image Resize failed", resizeErr);
                        }
                    } else if (isVideo) {
                        try {
                            const tempInput = path.join(os.tmpdir(), `input_${Date.now()}.mp4`);
                            const tempOutput = path.join(os.tmpdir(), `output_${Date.now()}.mp4`);

                            await fs.writeFile(tempInput, buffer);

                            // Compress Video using ffmpeg
                            // Extreme Compression: 8fps, CRF 40, 300k bitrate, ultrafast
                            await execAsync(`ffmpeg -y -i "${tempInput}" -vf "scale=512:512:force_original_aspect_ratio=decrease,fps=10" -c:v libx264 -preset ultrafast -crf 40 -b:v 300k -maxrate 300k -bufsize 600k -an "${tempOutput}"`);

                            buffer = await fs.readFile(tempOutput);

                            // Cleanup
                            await fs.unlink(tempInput).catch(() => { });
                            await fs.unlink(tempOutput).catch(() => { });
                        } catch (videoErr) {
                            console.error("Video Compression failed", videoErr);
                            // Continue with original buffer if compression fails, or throw? 
                            // If it fails, likely original will fail too, but let's try.
                        }
                    }

                    // Check for background removal (Only for Images)
                    const isRemoveBg = args.includes("nobg") || args.includes("removebg");
                    if (isImage && isRemoveBg && config.removeBgApiKey) {
                        try {
                            // Convert Buffer to Uint8Array for Blob compatibility
                            const uint8Array = new Uint8Array(buffer);
                            const blob = new Blob([uint8Array], { type: 'image/png' });

                            const formData = new FormData();
                            formData.append('image_file', blob, 'image.png');
                            formData.append('size', 'auto');

                            const res = await fetch('https://api.remove.bg/v1.0/removebg', {
                                method: 'POST',
                                headers: {
                                    'X-Api-Key': config.removeBgApiKey
                                },
                                body: formData
                            });

                            if (res.ok) {
                                const arrayBuffer = await res.arrayBuffer();
                                buffer = Buffer.from(arrayBuffer);
                            } else {
                                const err = await res.json();
                                throw new Error(`RemoveBG Error: ${(err as any).errors?.[0]?.title || res.statusText}`);
                            }
                        } catch (bgError) {
                            console.error("RemoveBG Failed:", bgError);
                            await sock.sendMessage(remoteJid, { text: `ΓÜá∩╕Å Remove BG failed: ${(bgError as any).message}. Sending normal sticker...` }, { quoted: msg });
                        }
                    } else if (isImage && isRemoveBg && !config.removeBgApiKey) {
                        await sock.sendMessage(remoteJid, { text: `ΓÜá∩╕Å Remove BG API Key not configured in dashboard. Sending normal sticker...` }, { quoted: msg });
                    }


                    // Convert
                    const sticker = new Sticker(buffer as Buffer, {
                        pack: (config as any).botName || "HAZA-WA Bot",
                        author: "By " + ((config as any).botName || "HAZA-WA Bot"),
                        type: "full", // full, crop, circle
                        quality: 15 // Extreme quality reduction for size
                    });

                    const stickerBuffer = await sticker.toBuffer();

                    // Send
                    await sock.sendMessage(remoteJid, { sticker: stickerBuffer }, { quoted: msg });
                    await sock.sendMessage(remoteJid, { react: { text: "Γ£à", key: msg.key } });

                } catch (e) {
                    console.error("Sticker generation failed", e);
                    await sock.sendMessage(remoteJid, { text: "Γ¥î Failed to create sticker. Error: " + (e as any).message }, { quoted: msg });
                }
                break;
            }

            case "menu":
            case "help": {
                const botName = (config as any).botName || "HAZA-WA Bot";
                const menu = `
≡ƒñû *${botName} Menu* ≡ƒñû

≡ƒôî *Commands:*
ΓÇó *#sticker* / *#s*: Convert Image/Video to Sticker
  - Supports Images, GIFs, and Videos (max ${(config as any).maxStickerDuration || 10}s)
  - Use *#sticker nobg* to remove background (Images only)
ΓÇó *#ping*: Check Bot Status
ΓÇó *#uptime*: Check Session Uptime
ΓÇó *#id*: Get Chat ID

_Made with Γ¥ñ∩╕Å_
`;
                await sock.sendMessage(remoteJid, { text: menu }, { quoted: msg });
                break;
            }

            default:
                // Ignore unknown commands
                break;
        }
    } catch (e) {
        console.error("Bot command error", e);
    }
}

import makeWASocket, {
    DisconnectReason,
    fetchLatestBaileysVersion,
    makeCacheableSignalKeyStore,
    WASocket,
    ConnectionState
} from "@whiskeysockets/baileys";
import { prisma } from "@/lib/prisma";
import { usePrismaAuthState } from "./auth/usePrismaAuthState";
import { Server } from "socket.io";
import pino from "pino";
import { bindSessionStore } from "./store";
import { syncGroups } from "./store/groups";
import { bindContactSync } from "./store/contacts";
import { bindAutoReply } from "./store/autoreply";
import { bindPpGuard } from "./store/ppguard";

export class WhatsAppInstance {
    socket: WASocket | null = null;
    qr: string | null = null;
    rq: string | null = null;
    status: string = "DISCONNECTED";
    sessionId: string;
    userId: string;
    io: Server;
    config: any = {};
    startTime: Date | null = null;

    isStopped: boolean = false;

    constructor(sessionId: string, userId: string, io: Server) {
        this.sessionId = sessionId;
        this.userId = userId;
        this.io = io;
    }

    async init() {
        this.isStopped = false; // Reset stop flag on init
        const sessionData = await prisma.session.findUnique({ where: { sessionId: this.sessionId } });
        this.config = sessionData?.config || {};
        
        const { state, saveCreds } = await usePrismaAuthState(this.sessionId);
        const { version } = await fetchLatestBaileysVersion();

        this.socket = makeWASocket({
            version,
            logger: pino({ level: process.env.BAILEYS_LOG_LEVEL || "error" }) as any,
            printQRInTerminal: false,
            auth: {
                creds: state.creds,
                keys: makeCacheableSignalKeyStore(state.keys, pino({ level: process.env.BAILEYS_LOG_LEVEL || "error" }) as any),
            },
            browser: ["HAZA-WA", "Chrome", "1.0.0"],
            markOnlineOnConnect: true,
            syncFullHistory: true, // Enable history sync to get contacts
        });
        
        // Bind Store for DB Sync (handles incoming messages)
        bindSessionStore(this.socket, this.sessionId, this.io);
        
        // Bind Contact Sync (handles contacts.update and messaging-history.set events)
        bindContactSync(this.socket, this.sessionId);

        this.socket.ev.on("creds.update", saveCreds);

        this.socket.ev.on("connection.update", async (update) => {
             await this.handleConnectionUpdate(update);
        });
    }

    async handleConnectionUpdate(update: Partial<ConnectionState>) {
        const { connection, lastDisconnect, qr } = update;

        try {
            if (qr) {
                if (this.isStopped) return; // Don't emit QR if stopped
                this.qr = qr;
                this.status = "SCAN_QR";
                
                // Emit QR to Socket Room
                this.io?.to(this.sessionId).emit("connection.update", { status: this.status, qr });
                
                // Update DB
                await prisma.session.update({
                    where: { sessionId: this.sessionId },
                    data: { qr, status: "SCAN_QR" }
                });
            }
            
            if (connection === "close") {
                const code = (lastDisconnect?.error as any)?.output?.statusCode;
                const isLoggedOut = code === DisconnectReason.loggedOut;
                
                // Only reconnect if NOT logged out AND NOT explicitly stopped
                const shouldReconnect = !isLoggedOut && !this.isStopped;
                
                // Determine status based on reason
                if (isLoggedOut) {
                    this.status = "LOGGED_OUT";
                } else if (this.isStopped) {
                    this.status = "STOPPED";
                } else {
                    this.status = "DISCONNECTED";
                }
                
                this.io?.to(this.sessionId).emit("connection.update", { status: this.status, qr: null });
                 
                // Use try-catch specifically for update as session might be deleted
                try {
                    await prisma.session.update({
                        where: { sessionId: this.sessionId },
                        data: { status: this.status, qr: null }
                    });
                } catch (e) {
                    // Ignore if session not found (deleted)
                }

                if (shouldReconnect) {
                    // Connection lost unexpectedly, reconnect
                    this.init();
                } else if (isLoggedOut) {
                    // Explicit logout: delete credentials
                    console.log(`Session ${this.sessionId} logged out. Deleting credentials...`);
                    try {
                        await prisma.$transaction([
                            prisma.session.update({
                                where: { sessionId: this.sessionId },
                                data: { status: "LOGGED_OUT", qr: null }
                            }),
                            prisma.authState.deleteMany({
                                where: { sessionId: this.sessionId }
                            })
                        ]);
                    } catch (e) { /* ignore */ }
                    this.socket = null;
                    this.config = {}; // Clear config cache
                    console.log(`Session ${this.sessionId} credentials deleted.`);
                } else if (this.isStopped) {
                    // Stopped: preserve credentials for future restart
                    console.log(`Session ${this.sessionId} stopped. Credentials preserved for auto-login.`);
                    this.socket = null;
                }
            }


            if (connection === "open") {
                this.status = "CONNECTED";
                this.qr = null;
                this.startTime = new Date();
                
                this.io?.to(this.sessionId).emit("connection.update", { status: this.status, qr: null });
                
                // Sync Groups from WhatsApp (with error handling)
                try {
                    await syncGroups(this.socket as WASocket, this.sessionId);
                } catch (e) {
                    console.error("Group sync failed:", e);
                }
                
                // Bind Auto Reply
                bindAutoReply(this.socket as WASocket, this.sessionId);
                
                // Bind PP Guard
                bindPpGuard(this.socket as WASocket, this.sessionId);

                await prisma.session.update({
                    where: { sessionId: this.sessionId },
                    data: { status: "CONNECTED", qr: null }
                });
                
                console.log(`Session ${this.sessionId} connected and synced successfully`);
            }
        } catch (error: any) {
            // Catch global errors in handler (like Record Not Found if session deleted mid-process)
            if (error.code === 'P2025') {
                console.warn(`Session ${this.sessionId} record not found during update. Stopping instance.`);
                this.socket?.end(undefined);
                this.socket = null;
            } else {
                console.error("Error in handleConnectionUpdate:", error);
            }
        }
    }
}

import { prisma } from "@/lib/prisma";
import { WhatsAppInstance } from "./instance";
import { Server } from "socket.io";
import { initScheduler } from "@/lib/cron";

export class WhatsAppManager {
    private static instance: WhatsAppManager;
    private sessions: Map<string, WhatsAppInstance> = new Map();
    public io: Server | null = null;
    
    private constructor() {
        initScheduler();
    }

    public static getInstance(): WhatsAppManager {
        if (!WhatsAppManager.instance) {
            WhatsAppManager.instance = new WhatsAppManager();
        }
        return WhatsAppManager.instance;
    }

    setup(io: Server) {
        this.io = io;
    }

    async loadSessions() {
        if (!this.io) throw new Error("Socket.IO not initialized in WhatsAppManager");
        const sessions = await prisma.session.findMany({
            where: { status: { not: "LOGGED_OUT" } }
        });

        for (const session of sessions) {
            const instance = new WhatsAppInstance(session.sessionId, session.userId, this.io);
            this.sessions.set(session.sessionId, instance);
            await instance.init();
        }
        console.log(`Loaded ${sessions.length} sessions.`);
    }

    async createSession(userId: string, name: string, customSessionId?: string) {
        // Fallback to global IO if instance IO is missing (Next.js Context Issue)
        if (!this.io && (global as any).io) {
            this.io = (global as any).io;
        }

        if (!this.io) {
             console.error("Socket.IO not initialized in WhatsAppManager, and global fallback failed.");
             throw new Error("Socket.IO not initialized");
        }
        
        // Use custom ID if provided, otherwise generate random
        const sessionId = customSessionId || Math.random().toString(36).substring(7);

        const session = await prisma.session.create({
            data: {
                userId,
                name,
                sessionId,
                status: "DISCONNECTED",
                botConfig: {
                    create: {
                        enabled: true,
                        botMode: "OWNER",
                        autoReplyMode: "ALL"
                    }
                }
            }
        });

        const instance = new WhatsAppInstance(sessionId, userId, this.io);
        this.sessions.set(sessionId, instance);
        await instance.init();

        return session;
    }

    public getInstance(sessionId: string) {
        return this.sessions.get(sessionId);
    }
    
    async deleteSession(sessionId: string) {
        const instance = this.sessions.get(sessionId);
        if (instance) {
             // Logout/Close socket
             instance.socket?.end(undefined);
             this.sessions.delete(sessionId);
        }
        await prisma.session.delete({ where: { sessionId } });
    }

    async stopSession(sessionId: string) {
        const instance = this.sessions.get(sessionId);
        if (instance) {
            instance.isStopped = true; // Prevent auto-reconnect
            instance.socket?.end(undefined);
            instance.status = "STOPPED";
            this.io?.to(sessionId).emit("connection.update", { status: "STOPPED", qr: null });
            await prisma.session.update({
                where: { sessionId },
                data: { status: "STOPPED" }
            });
        }
    }

    async startSession(sessionId: string) {
        // If already running, do nothing
        const existingInstance = this.sessions.get(sessionId);
        if (existingInstance && existingInstance.status === "CONNECTED") {
            return;
        }

        const session = await prisma.session.findUnique({ where: { sessionId } });
        if (!session) throw new Error("Session not found");

        // Re-initialize
        let instance = this.sessions.get(sessionId);
        if (!instance) {
            instance = new WhatsAppInstance(sessionId, session.userId, this.io!);
            this.sessions.set(sessionId, instance);
        }
        
        await instance.init();
    }

    async restartSession(sessionId: string) {
        await this.stopSession(sessionId);
        // Small delay to ensure cleanup
        await new Promise(resolve => setTimeout(resolve, 1000));
        await this.startSession(sessionId);
    }
}

