import { prisma } from "@/lib/prisma";
import { waManager } from "./manager";

const checkScheduledMessages = async () => {
    try {
        const now = new Date();
        console.log(`[Scheduler] Checking for messages due before ${now.toISOString()}...`);

        const pendingMessages = await prisma.scheduledMessage.findMany({
            where: {
                status: "PENDING",
                sendAt: { lte: now }
            }
        });

        if (pendingMessages.length > 0) {
            console.log(`[Scheduler] Found ${pendingMessages.length} pending messages.`);
        }

        for (const msg of pendingMessages) {
            const instance = waManager.getInstance(msg.sessionId);

            if (instance?.socket) {
                try {
                    let content: any = {};
                    // Simple text support for now, expand for media later
                    if (msg.mediaUrl) {
                        const url = msg.mediaUrl;
                        const type = msg.mediaType || 'image'; // Default to image if null

                        if (type === 'video') {
                            content = { video: { url }, caption: msg.content };
                        } else if (type === 'document') {
                            content = { document: { url }, caption: msg.content, fileName: 'file', mimetype: 'application/octet-stream' };
                        } else {
                            content = { image: { url }, caption: msg.content };
                        }
                    } else {
                        content = { text: msg.content };
                    }

                    await instance.socket.sendMessage(msg.jid, content);

                    await prisma.scheduledMessage.update({
                        where: { id: msg.id },
                        data: { status: "SENT" }
                    });
                    console.log(`[Scheduler] Msg ${msg.id} sent to ${msg.jid}`);

                } catch (err) {
                    console.error(`[Scheduler] Failed to send scheduled msg ${msg.id}`, err);
                    await prisma.scheduledMessage.update({
                        where: { id: msg.id },
                        data: { status: "FAILED" }
                    });
                }
            } else {
                console.log(`[Scheduler] Session ${msg.sessionId} not connected for scheduled msg ${msg.id}`);
                // Optionally mark as failed or leave pending
            }
        }
    } catch (e) {
        console.error("[Scheduler] Error:", e);
    }
};

export function startScheduler() {
    console.log("Starting Message Scheduler...");

    // Run immediately on start
    checkScheduledMessages();

    // Then run every 30 seconds
    setInterval(checkScheduledMessages, 30 * 1000);
}

import { prisma } from "@/lib/prisma";
import type { WASocket } from "@whiskeysockets/baileys";
import { normalizeMessageContent } from "@whiskeysockets/baileys";

// Helper for permission check (Deduplicate from command-handler if possible, but keep simple here)
function canAutoReply(config: any, fromMe: boolean, senderJid: string): boolean {
    if (!config || !config.enabled) return false;

    // Auto Reply Specific Mode
    const mode = config.autoReplyMode || 'ALL';

    if (fromMe) {
        // If mode is OWNER, it triggers for ME? 
        // Auto Reply usually replies TO someone. 
        // If I send a message, and mode is OWNER, should it reply to me? 
        // User requested "Self Mode" -> Use case: Snippets.
        // So yes, if fromMe checks out.

        // However, standard auto-reply logic (replying to incoming) should be blocked if fromMe is true AND mode is ALL?
        // No, typically Auto Reply doesn't trigger on own messages to prevent unexpected loops.
        // But for "Self Mode" (Macros), it MUST trigger on own messages.

        if (mode === 'OWNER') return true;
        if (mode === 'ALL') return false; // Standard auto-reply ignores self

        // Specific? 
        return false;
    } else {
        // Incoming message from others
        if (mode === 'OWNER') return false; // Owner only acts on Owner messages
        if (mode === 'ALL') return true;

        if (mode === 'SPECIFIC') {
            const allowedJids = config.autoReplyAllowedJids || [];
            if (Array.isArray(allowedJids)) {
                return allowedJids.some((jid: string) => senderJid.includes(jid));
            }
        }

        if (mode === 'BLACKLIST') {
            const blockedJids = config.autoReplyBlockedJids || [];
            if (Array.isArray(blockedJids)) {
                const isBlocked = blockedJids.some((jid: string) => senderJid.includes(jid));
                return !isBlocked; // Return true if NOT blocked
            }
            return true; // If blacklist empty, allow all
        }
    }

    return false;
}

export async function bindAutoReply(sock: WASocket, sessionId: string) {
    sock.ev.on('messages.upsert', async ({ messages, type }) => {
        if (type !== 'notify') return;

        // Fetch session ID and Bot Config once per batch (optimization)
        const session = await prisma.session.findUnique({
            where: { sessionId },
            // @ts-ignore
            include: { botConfig: true }
        });

        if (!session) return;

        // @ts-ignore
        let config = (session as any).botConfig;

        if (!config) {
            console.log("AutoReply: No config found, creating default...");
            config = await prisma.botConfig.create({
                data: {
                    sessionId: session.id,
                    enabled: true,
                    botMode: 'OWNER',
                    autoReplyMode: 'ALL'
                }
            });
        }

        console.log(`AutoReply: Processing for ${sessionId}. Config:`, config ? "Found" : "Missing", config?.enabled ? "Enabled" : "Disabled");

        if (!config || !config.enabled) return;

        for (const msg of messages) {
            const fromMe = msg.key.fromMe || false;
            const remoteJid = msg.key.remoteJid;

            // Standardized Sender Logic
            const isGroup = remoteJid?.endsWith("@g.us") || false;
            const remoteJidAlt = msg.key.remoteJidAlt;
            let senderJid = (isGroup ? (msg.key.participant || msg.participant) : remoteJid);

            if (!isGroup && remoteJidAlt) {
                senderJid = remoteJidAlt;
            }

            if (!remoteJid || !senderJid) continue;

            // Check Permissions
            if (!canAutoReply(config, fromMe, senderJid)) continue;

            const content = normalizeMessageContent(msg.message);
            const text = content?.conversation || content?.extendedTextMessage?.text || ""; // Caption?

            if (!text) continue;

            try {
                // Fetch rules for this session
                const rules = await prisma.autoReply.findMany({
                    where: {
                        session: {
                            sessionId: sessionId
                        }
                    }
                });

                for (const rule of rules) {
                    let match = false;
                    const keyword = rule.keyword.toLowerCase();
                    const incoming = text.toLowerCase();

                    switch (rule.matchType) {
                        case 'EXACT':
                            match = incoming === keyword;
                            break;
                        case 'CONTAINS':
                            match = incoming.includes(keyword);
                            break;
                        case 'REGEX':
                            try {
                                const regex = new RegExp(rule.keyword, 'i');
                                match = regex.test(text); // Use original case for regex
                            } catch (e) {
                                console.error("Invalid regex in auto-reply", rule.keyword);
                            }
                            break;
                    }

                    if (match) {
                        // Check trigger context (GROUP, PRIVATE, or ALL)
                        const isGroup = remoteJid.endsWith('@g.us');
                        const triggerType = (rule as any).triggerType || 'ALL'; // Default to ALL if undefined

                        if (triggerType === 'GROUP' && !isGroup) continue;
                        if (triggerType === 'PRIVATE' && isGroup) continue;

                        console.log(`Auto-reply match: ${rule.keyword} -> ${remoteJid}`);

                        if (rule.isMedia && rule.mediaUrl) {
                            const url = rule.mediaUrl;
                            const isVideo = url.endsWith('.mp4') || url.endsWith('.avi') || url.endsWith('.mov');
                            const isDocument = url.endsWith('.pdf') || url.endsWith('.doc') || url.endsWith('.docx') || url.endsWith('.zip');

                            if (isVideo) {
                                await sock.sendMessage(remoteJid, {
                                    video: { url },
                                    caption: rule.response
                                }, { quoted: msg });
                            } else if (isDocument) {
                                await sock.sendMessage(remoteJid, {
                                    document: { url },
                                    caption: rule.response,
                                    mimetype: 'application/octet-stream', // Default mimetype
                                    fileName: url.split('/').pop() || 'document'
                                }, { quoted: msg });
                            } else {
                                // Default to Image
                                await sock.sendMessage(remoteJid, {
                                    image: { url },
                                    caption: rule.response
                                }, { quoted: msg });
                            }
                        } else {
                            await sock.sendMessage(remoteJid, { text: rule.response }, { quoted: msg });
                        }

                        break;
                    }
                }

            } catch (e) {
                console.error("Auto-reply error", e);
            }
        }
    });
}

import { prisma } from "@/lib/prisma";
import type { WASocket } from "@whiskeysockets/baileys";

/**
 * Sync contacts from WhatsApp to database.
 * Uses proper Baileys events for syncing and correct Session.id foreign key.
 */
export function bindContactSync(sock: WASocket, sessionId: string) {
    // First, get the database Session ID (cuid)
    let dbSessionId: string | null = null;
    
    // Initialize by fetching the session ID
    (async () => {
        const session = await prisma.session.findUnique({
            where: { sessionId },
            select: { id: true }
        });
        if (session) {
            dbSessionId = session.id;
            console.log(`Contact sync initialized for session ${sessionId} (db: ${dbSessionId})`);
        } else {
            console.error(`Session ${sessionId} not found for contact sync`);
        }
    })();

    // Handle contacts.update event (fires when contacts are updated)
    sock.ev.on('contacts.update', async (updates) => {
        if (!dbSessionId) {
            const session = await prisma.session.findUnique({ where: { sessionId }, select: { id: true } });
            if (!session) return;
            dbSessionId = session.id;
        }
        
        console.log(`Received ${updates.length} contact updates for session ${sessionId}`);
        for (const update of updates) {
            try {
                if (!update.id) continue;
                
                await prisma.contact.upsert({
                    where: { sessionId_jid: { sessionId: dbSessionId, jid: update.id } },
                    create: {
                        sessionId: dbSessionId,
                        jid: update.id,
                        name: update.name || update.notify,
                        notify: update.notify,
                        profilePic: update.imgUrl
                    },
                    update: {
                        name: update.name || undefined,
                        notify: update.notify || undefined,
                        profilePic: update.imgUrl || undefined
                    }
                });
            } catch (e) {
                console.error(`Failed to sync contact ${update.id}`, e);
            }
        }
    });

    // Also listen for messaging events to auto-create contacts
    sock.ev.on('messaging-history.set', async ({ chats, contacts, messages, isLatest }) => {
        if (!dbSessionId) {
            const session = await prisma.session.findUnique({ where: { sessionId }, select: { id: true } });
            if (!session) return;
            dbSessionId = session.id;
        }
        
        console.log(`Received messaging history: ${chats.length} chats, ${contacts?.length || 0} contacts, ${messages.length} messages`);
        
        // Sync chats as contacts (for personal chats)
        for (const chat of chats) {
            try {
                if (!chat.id || chat.id.includes('@g.us') || chat.id.includes('@broadcast')) continue;
                
                await prisma.contact.upsert({
                    where: { sessionId_jid: { sessionId: dbSessionId, jid: chat.id } },
                    create: {
                        sessionId: dbSessionId,
                        jid: chat.id,
                        name: chat.name || undefined,
                        notify: (chat as any).notify || undefined
                    },
                    update: {
                        name: chat.name || undefined
                    }
                });
            } catch (e) {
                console.error(`Failed to sync chat contact ${chat.id}`, e);
            }
        }
        
        // Sync explicit contacts
        if (contacts) {
            for (const contact of contacts) {
                try {
                    if (!contact.id) continue;
                    
                    await prisma.contact.upsert({
                        where: { sessionId_jid: { sessionId: dbSessionId, jid: contact.id } },
                        create: {
                            sessionId: dbSessionId,
                            jid: contact.id,
                            name: contact.name || contact.notify,
                            notify: contact.notify
                        },
                        update: {
                            name: contact.name || undefined,
                            notify: contact.notify || undefined
                        }
                    });
                } catch (e) {
                    console.error(`Failed to sync contact ${contact.id}`, e);
                }
            }
        }
        
        console.log(`Synced contacts from messaging history for session ${sessionId}`);
    });
}

import { prisma } from "@/lib/prisma";
import type { WASocket, GroupMetadata } from "@whiskeysockets/baileys";

export async function syncGroups(sock: WASocket, sessionId: string) {
    try {
        // Verify session exists and get the actual database ID
        const session = await prisma.session.findUnique({
            where: { sessionId },
            select: { id: true }
        });
        
        if (!session) {
            console.error(`Session ${sessionId} does not exist, cannot sync groups`);
            return;
        }

        // Use session.id (cuid) for foreign key, not sessionId string
        const dbSessionId = session.id;

        const groups = await sock.groupFetchAllParticipating();
        const groupList = Object.values(groups);

        console.log(`Found ${groupList.length} groups for session ${sessionId}`);

        for (const g of groupList) {
             try {
                 await prisma.group.upsert({
                     where: { sessionId_jid: { sessionId: dbSessionId, jid: g.id } },
                     create: {
                         sessionId: dbSessionId,
                         jid: g.id,
                         subject: g.subject,
                         description: g.desc,
                         ownerJid: g.owner,
                         creation: g.creation ? new Date(g.creation * 1000) : undefined,
                         restrict: g.restrict,
                         announce: g.announce,
                         participants: g.participants as any,
                         metadata: g as any
                     },
                     update: {
                         subject: g.subject,
                         description: g.desc,
                         ownerJid: g.owner,
                         restrict: g.restrict,
                         announce: g.announce,
                         participants: g.participants as any,
                         metadata: g as any
                     }
                 });
             } catch (e) {
                 console.error(`Failed to sync group ${g.id}`, e);
             }
        }
        console.log(`Synced ${groupList.length} groups for session ${sessionId}`);
    } catch (e) {
        console.error("Failed to sync groups", e);
    }
}

import { prisma } from "@/lib/prisma";
import type { WASocket, WAMessage, Contact } from "@whiskeysockets/baileys";
import { normalizeMessageContent } from "@whiskeysockets/baileys";
import { onMessageReceived, onMessageSent, dispatchWebhook, downloadAndSaveMedia } from "@/lib/webhook";
import { handleBotCommand, setSessionStartTime } from "../bot/command-handler";

import { Server } from "socket.io";

export const bindSessionStore = (sock: WASocket, sessionId: string, io: Server | null) => {
    // Set start time for uptime command
    setSessionStartTime(sessionId);

    // First, get the database Session ID (cuid)
    let dbSessionId: string | null = null;
    
    // Initialize by fetching the session ID
    (async () => {
        const session = await prisma.session.findUnique({
            where: { sessionId },
            select: { id: true }
        });
        if (session) {
            dbSessionId = session.id;
            console.log(`Message store initialized for session ${sessionId} (db: ${dbSessionId})`);
        } else {
            console.error(`Session ${sessionId} not found for message store`);
        }
    })();
    
    // Handle Messages
    sock.ev.on('messages.upsert', async ({ messages, type }) => {
        // Process all message types: notify, append, and history sync
        if (type !== 'notify' && type !== 'append') {
            // For history sync, we still want to save messages
            console.log(`Received ${messages.length} messages of type: ${type}`);
        }

        // Emit to socket room for real-time frontend updates
        if (type === 'notify' || type === 'append') {
            io?.to(sessionId).emit('message.upsert', { messages, type });
        }

        // Ensure we have the database session ID
        if (!dbSessionId) {
            const session = await prisma.session.findUnique({ where: { sessionId }, select: { id: true } });
            if (!session) return;
            dbSessionId = session.id;
        }

        const processedMessages = [];

        for (const msg of messages) {
            try {
                const savedMessage = await processAndSaveMessage(msg, dbSessionId, sessionId, type === 'notify');
                if (savedMessage) {
                    processedMessages.push(savedMessage);
                }
                
                // Execute Bot Commands (Only for Notify / New Messages)
                if (type === 'notify' && savedMessage) {
                   // Run in background, don't await strictly to not block saving
                   handleBotCommand(sock, sessionId, msg).catch(e => console.error("Bot Handler Error", e));
                }
            } catch (error) {
                console.error("Error saving message", error);
            }
        }

        // Emit to socket room for real-time frontend updates
        if (processedMessages.length > 0) {
            io?.to(sessionId).emit('message.update', processedMessages);
        }
    });

    // Handle Message History Sync (when connecting for the first time or syncing)
    sock.ev.on('messaging-history.set', async ({ messages, chats, contacts, isLatest }) => {
        console.log(`History sync: ${messages?.length || 0} messages, ${chats?.length || 0} chats, ${contacts?.length || 0} contacts, latest: ${isLatest}`);
        
        // Ensure we have the database session ID
        if (!dbSessionId) {
            const session = await prisma.session.findUnique({ where: { sessionId }, select: { id: true } });
            if (!session) return;
            dbSessionId = session.id;
        }

        // Save all historical messages
        if (messages && messages.length > 0) {
            console.log(`Syncing ${messages.length} historical messages...`);
            for (const msg of messages) {
                try {
                    await processAndSaveMessage(msg, dbSessionId, sessionId, false);
                } catch (error) {
                    console.error("Error saving historical message", error);
                }
            }
            console.log(`Finished syncing ${messages.length} historical messages`);
        }


        // Note: Contacts and Chats are synced by src/modules/whatsapp/store/contacts.ts
        // We only handle messages here to avoid P2002 Unique Constraint Race Conditions.
        console.log(`Finished syncing ${messages.length} historical messages`);
    });

    // Handle Contacts Upsert
    sock.ev.on('contacts.upsert', async (contacts) => {
        // Ensure we have the database session ID
        if (!dbSessionId) {
            const session = await prisma.session.findUnique({ where: { sessionId }, select: { id: true } });
            if (!session) return;
            dbSessionId = session.id;
        }

        for (const c of contacts) {
             try {
                if (!c.id) continue;
                await prisma.contact.upsert({
                    where: { sessionId_jid: { sessionId: dbSessionId, jid: c.id } },
                    create: {
                        sessionId: dbSessionId,
                        jid: c.id,
                        // @ts-ignore
                        lid: c.lid || undefined,
                        name: c.name || c.notify || c.verifiedName,
                        notify: c.notify,
                        // @ts-ignore
                        verifiedName: c.verifiedName,
                        profilePic: c.imgUrl || undefined,
                        data: c as any
                    },
                    update: {
                        // @ts-ignore
                        lid: c.lid || undefined,
                        name: c.name || undefined,
                        notify: c.notify || undefined,
                        // @ts-ignore
                        verifiedName: c.verifiedName || undefined,
                        profilePic: c.imgUrl || undefined,
                        data: c as any
                    }
                });
                
                // Dispatch webhook for contact update
                dispatchWebhook(sessionId, "contact.update", { jid: c.id, name: c.name, notify: c.notify });
             } catch (e) {
                 console.error("Error saving contact", e);
             }
        }
    });

    // Handle Message Status Updates
    sock.ev.on('messages.update', async (updates) => {
        if (!dbSessionId) return;
        
        for (const update of updates) {
            try {
                const keyId = update.key?.id;
                if (!keyId) continue;

                const statusMap: Record<number, string> = {
                    0: 'PENDING',
                    1: 'SENT',
                    2: 'DELIVERED',
                    3: 'READ',
                    4: 'READ', // Played
                };

                const status = statusMap[update.update?.status || 0] || 'PENDING';

                await prisma.message.updateMany({
                    where: { sessionId: dbSessionId, keyId },
                    data: { status: status as any }
                });

                // Dispatch webhook for message status update
                dispatchWebhook(sessionId, "message.status", {
                    keyId,
                    remoteJid: update.key?.remoteJid,
                    status
                });
            } catch (e) {
                console.error("Error updating message status", e);
            }
        }
    });
};

async function processAndSaveMessage(msg: WAMessage, dbSessionId: string, sessionId: string, triggerWebhook: boolean) {
    const keyId = msg.key.id;
    const remoteJid = msg.key.remoteJid;
    const fromMe = msg.key.fromMe;
    const pushName = msg.pushName;
    const timestamp = msg.messageTimestamp 
        ? new Date((typeof msg.messageTimestamp === 'number' ? msg.messageTimestamp : Number(msg.messageTimestamp)) * 1000)
        : new Date();
    
    // Filter out Protocol & Empty Messages
    if (!msg.message) return false;
    if (!keyId || !remoteJid) return false;
    
    // Ignore specific technical message types
    const messageKeys = Object.keys(msg.message);
    const ignoredTypes = [
        'protocolMessage', 
        'senderKeyDistributionMessage', 
        'reactionMessage', // Optional: User might want reactions, but usually "kosong" means junk
        'keepInChatMessage' 
    ];
    
    // If message only contains ignored types, skip
    if (messageKeys.every(k => ignoredTypes.includes(k))) {
        console.log(`Skipping technical message: ${keyId} (${messageKeys.join(', ')})`);
        return null;
    }

    // Check if message already exists to avoid duplicates
    // Baileys 'notify' event can sometimes trigger multiple times or for history
    // Baileys 'notify' event can sometimes trigger multiple times or for history
    const existingMessage = await prisma.message.findUnique({
        where: { sessionId_keyId: { sessionId: dbSessionId, keyId: keyId! } },
        select: { id: true, status: true }
    });

    if (existingMessage) {
        // Message exists! Update status if changed, but DO NOT re-trigger webhooks/bot
        if (fromMe && existingMessage.status !== 'SENT') {
             await prisma.message.update({
                where: { id: existingMessage.id },
                data: { status: 'SENT' }
            });
        }
        // Return null to indicate "Not New"
        return null;
    }

    // Debug fromMe issue (Keep this for a while)
    if (fromMe === undefined || fromMe === null) {
        console.log(`[DEBUG] Message ${keyId} has fromMe=${fromMe}. Key:`, JSON.stringify(msg.key));
    }

    const messageContent = normalizeMessageContent(msg.message);
    let text = "";
    let messageType = "TEXT";

    // Extract content based on message type
    if (messageContent?.conversation) {
        text = messageContent.conversation;
    } else if (messageContent?.extendedTextMessage?.text) {
        text = messageContent.extendedTextMessage.text;
    } else if (messageContent?.imageMessage) {
        messageType = "IMAGE";
        text = messageContent.imageMessage.caption || "";
    } else if (messageContent?.videoMessage) {
        messageType = "VIDEO";
        text = messageContent.videoMessage.caption || "";
    } else if (messageContent?.audioMessage) {
        messageType = "AUDIO";
    } else if (messageContent?.documentMessage) {
        messageType = "DOCUMENT";
        text = messageContent.documentMessage.fileName || "";
    } else if (messageContent?.stickerMessage) {
        messageType = "STICKER";
    } else if (messageContent?.locationMessage) {
        messageType = "LOCATION";
        text = `${messageContent.locationMessage.degreesLatitude},${messageContent.locationMessage.degreesLongitude}`;
    } else if (messageContent?.contactMessage) {
        messageType = "CONTACT";
        text = messageContent.contactMessage.displayName || "";
    }

    // Determine effective participant for groups
    // Determine effective participant for groups with standard logic
    const isGroup = remoteJid.endsWith("@g.us");
    const remoteJidAlt = msg.key.remoteJidAlt; // LID/Phone JID handling
    let senderJid = fromMe ? undefined : (isGroup ? (msg.key.participant || msg.participant) : remoteJid);
    
    // Prefer remoteJidAlt for DMs if available (matches webhook logic)
    if (!fromMe && !isGroup && remoteJidAlt) {
        senderJid = remoteJidAlt;
    }


    // Download Media First (to save URL to DB)
    let fileUrl: string | null = null;
    try {
        fileUrl = await downloadAndSaveMedia(msg, sessionId);
    } catch (e) {
        console.error("Error downloading media in store", e);
    }

    const newMessage = await prisma.message.create({
        data: {
            sessionId: dbSessionId,
            remoteJid,
            senderJid,
            fromMe: fromMe || false,
            keyId,
            pushName,
            type: messageType as any,
            content: text,
            mediaUrl: fileUrl, // Save Media URL
            status: fromMe ? "SENT" : "PENDING",
            timestamp
        }
    });

    // Ensure contact exists (Upsert Contact)
    if (remoteJid && !remoteJid.includes('@g.us') && !remoteJid.includes('status@broadcast')) {
         const contactData: any = {
             sessionId: dbSessionId,
             jid: remoteJid
         };

         // Only update name/notify if message is FROM the contact (not from me)
         if (!fromMe) {
             if (pushName) contactData.notify = pushName;
             if (pushName) contactData.name = pushName;
         }

         await prisma.contact.upsert({
            where: { sessionId_jid: { sessionId: dbSessionId, jid: remoteJid } },
            create: {
                sessionId: dbSessionId,
                jid: remoteJid,
                notify: !fromMe ? pushName : undefined,
                name: !fromMe ? pushName : undefined,
                // @ts-ignore
                remoteJidAlt: remoteJidAlt || undefined
            },
            update: !fromMe ? {
                notify: pushName,
                // Only update name if it was null? Or always? Let's just update notify usually.
                // But Baileys often sends name in pushName.
                // @ts-ignore
                remoteJidAlt: remoteJidAlt || undefined // Update Alt JID if we see it
            } : {}
        });
    }

    // Trigger webhook for new messages only (not history sync)
    // AND filter duplicates is implicitly done because we return 'false' above if existing
    if (triggerWebhook) {
        if (fromMe) {
            onMessageSent(sessionId, msg, fileUrl).catch(e => console.error("Error in onMessageSent", e));
        } else {
            // Pass the fileUrl we just downloaded
            onMessageReceived(sessionId, msg, fileUrl).catch(e => console.error("Error in onMessageReceived", e));
        }
    }

    return newMessage; // Is New Message = True (Return Object)
}
